INSERT INTO public.path (id, name, description, tier, pillar, "subMode", "sessionsCount", classifications, "triggerSignals") VALUES ('a80a9cba-2938-57e8-9530-54c41c19551e', 'Nervous System Basics', 'Emotional Well-being  ·  General Emotional  ·  Capacity Erosion', 'free', 'emotional', 'general_emotional', 5, 'Capacity Erosion', 'enrollment:onboarding; flag:None — all users matching classification');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('bb3c7d4d-e0e0-5d85-8d87-c51f6b85f6a9', 'a80a9cba-2938-57e8-9530-54c41c19551e', 1, 'Why your body is doing what it''s doing', 'When you are under sustained stress, your body is not malfunctioning. It is doing exactly what it was designed to do. The racing heart, the shallow breathing, the inability to sleep or the inability to stay awake, the tight shoulders, the brain that will not quiet down — these are all features of a nervous system responding to perceived threat. The problem is not your body. The problem is that the threat has become chronic. The human nervous system was designed for acute stress — a predator, a physical danger, a short-term crisis. It responds to that kind of stress brilliantly. But it was not designed for the kind of stress most people carry today: relentless, low-grade, never-fully-resolving pressure that keeps the system activated without ever allowing it to complete its cycle. Understanding this changes how you relate to your own symptoms. You are not weak. You are not broken. You are a nervous system that has been running in activation mode for longer than it was built to sustain. That is a systems problem, not a character problem. And systems problems have systems solutions. The first step is just this: noticing. Noticing what your body is doing right now, in this moment. Not fixing it. Not judging it. Just observing it as information.', 'This week: once a day, take 60 seconds to notice what your body is doing. No fixing — just noticing. Name it: activated, quiet, tight, heavy, buzzing.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('4f3a41b6-7ec8-5cac-a021-f6ccd4ebeee0', 'bb3c7d4d-e0e0-5d85-8d87-c51f6b85f6a9', 1, 'What does your nervous system feel like right now, in your body? Where are you holding tension, activation, or numbness?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('623628a7-724d-5542-8ec4-09e351b3f700', 'bb3c7d4d-e0e0-5d85-8d87-c51f6b85f6a9', 2, 'When you think about the past few weeks, what has kept your system activated — what has been the persistent source of pressure?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('fe1e7568-04d2-593b-b950-a83ee1646632', 'bb3c7d4d-e0e0-5d85-8d87-c51f6b85f6a9', 3, 'Have there been times when your nervous system felt more regulated? What was different then?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('a75ca704-13cd-503f-93c0-c907baa038c2', 'a80a9cba-2938-57e8-9530-54c41c19551e', 2, 'The stress cycle — completing it versus getting stuck', 'Here is something most people do not know about stress: the stress response has a beginning, a middle, and an end. When the response completes — when the body moves through activation and returns to baseline — the system resets. When it does not complete, the stress stays in the body, accumulating. Think about animals in the wild. A gazelle chased by a lion that escapes will literally shake for a few minutes afterward. That shaking is the nervous system completing its cycle — discharging the activation energy that built up during the threat. Then the gazelle goes back to grazing. It does not lie awake that night ruminating about the lion. Humans have largely lost this. We move from stressor to stressor without completing the cycle between them. We use cognitive override — telling ourselves to calm down, to be rational, to move on — which suppresses the body''s need to discharge without actually resolving the activation. The result is a body that is chronically activated, carrying the residue of dozens of incomplete stress cycles. The good news is that the cycle can be completed, even after the fact. Movement, breath, shaking, crying, even laughter — these are all completion mechanisms. The body knows how to finish what it started. It just needs permission and space.', 'This week: after one stressful event, do something physical before you move on — a 10-minute walk, 5 minutes of deliberate breathing, anything that involves the body. Notice what happens.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('f25137ca-d4a6-562e-95f4-7b4ae8827be1', 'a75ca704-13cd-503f-93c0-c907baa038c2', 1, 'Think about the last time you felt genuinely calm and restored — not just distracted, but actually settled. What allowed that to happen?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('776f06c0-36ca-53f8-af92-55a966262e7f', 'a75ca704-13cd-503f-93c0-c907baa038c2', 2, 'What do you do currently when you are stressed that you think is helping but might be preventing the cycle from completing?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('5f65a39d-f03f-55b7-96d7-d87a627d6676', 'a75ca704-13cd-503f-93c0-c907baa038c2', 3, 'What completion mechanisms have worked for you in the past — movement, breath, crying, talking, physical activity?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('91505674-f2bb-5c47-a3c7-9fc4650cddf6', 'a80a9cba-2938-57e8-9530-54c41c19551e', 3, 'Three regulation tools for the next 72 hours', 'You do not need a complicated system. You need three things that actually work for you, that you can actually do, in the actual life you have right now. Regulation does not require an hour. It does not require silence, a yoga mat, or a perfect environment. It requires a nervous system intervention — something that communicates safety to the body, interrupts the activation spiral, and creates even a brief window of reset. The three tools that have the strongest physiological basis for most people are: slow extended exhale breathing, which activates the parasympathetic nervous system directly; cold water on the face or wrists, which triggers the diving reflex and slows the heart rate; and deliberate slow movement, which completes the stress cycle without requiring high energy. None of these are magic. None of them will undo a week of chronic stress in five minutes. But each of them shifts the physiological state in a measurable direction. And small shifts, used consistently, accumulate. You are not trying to solve the problem in one session. You are trying to give your system something it can use right now, today, this week.', 'This week: pick one of the three tools and use it once a day at the same time, regardless of how you feel. Set a reminder if needed.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('77bd94ee-0c16-5f21-bee7-224fa1cf3db6', '91505674-f2bb-5c47-a3c7-9fc4650cddf6', 1, 'Of the three tools described — breathing, cold water, slow movement — which feels most accessible and realistic for your current life?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('59c5f627-a3ed-5171-8fc5-a1adb5d42d8a', '91505674-f2bb-5c47-a3c7-9fc4650cddf6', 2, 'What gets in the way of using regulation tools when you actually need them most — what is the specific obstacle?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('1968beb3-9b10-565e-adfb-a15f15d53e84', '91505674-f2bb-5c47-a3c7-9fc4650cddf6', 3, 'When in your day would it be easiest to use one of these tools consistently — not when you feel terrible, but as a daily practice?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('8a9580bf-c799-5804-acde-89f51e5bcd81', 'a80a9cba-2938-57e8-9530-54c41c19551e', 4, 'Sleep and rest are not the same thing', 'Sleep is a biological necessity. Rest is a nervous system state. You can sleep eight hours and wake up exhausted. You can rest for twenty minutes and feel genuinely restored. The difference is what the nervous system is doing. Most people who are chronically stressed have poor sleep quality not because they are not sleeping enough but because their nervous system is still partially activated during sleep. The brain does not fully enter the restorative sleep stages because the threat signal has not been cleared. You wake up as tired as you went to bed. Real rest — the kind that actually restores capacity — requires the nervous system to feel safe. Not just horizontal. Not just eyes closed. Safe. This is why watching stressful content before bed, lying awake ruminating, or using screens that simulate daylight disrupts rest so significantly. The system gets the signal that it is not safe to downregulate. The goal for this week is not to fix your sleep. It is to create one consistent signal of safety for your nervous system before it is supposed to rest. One thing that communicates: the threat is over for now. You can let go.', 'This week: choose one pre-sleep change and try it for five consecutive nights. Not a full routine overhaul — just one thing. Notice whether anything shifts.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('0ae13846-afb1-5e39-8edc-fc813c12ef07', '8a9580bf-c799-5804-acde-89f51e5bcd81', 1, 'How would you honestly describe your sleep right now — what is actually happening, not what you wish was happening?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('5b9b6e9c-359f-52d9-b745-a86b868d8911', '8a9580bf-c799-5804-acde-89f51e5bcd81', 2, 'What are you typically doing in the hour before you try to sleep — and how activated is your nervous system when you lie down?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('b86d273c-c7a5-50a4-a850-8b5e21376f9a', '8a9580bf-c799-5804-acde-89f51e5bcd81', 3, 'What one change to your pre-sleep environment or routine might create a stronger safety signal for your nervous system?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('d4c05990-e863-5554-8ce2-71c1146aea1e', 'a80a9cba-2938-57e8-9530-54c41c19551e', 5, 'Building a minimal recovery routine that works with your real life', 'The goal is not to add another thing you should be doing and are failing at. The goal is to identify the smallest possible set of practices that give your nervous system a real chance to recover — and to actually do them. Most recovery routines fail not because they are wrong but because they are sized for a life with more margin than the person currently has. If you are in Capacity Erosion, you do not have the bandwidth for a 90-minute morning practice. You need something that takes five minutes and actually happens. The minimal recovery routine has three components: one daily anchor that takes under five minutes and happens at the same time each day; one weekly longer practice that gives your system a real reset — a walk, time in nature, something physical, something quiet; and one thing you stop doing because it is accelerating the depletion rather than helping it. That is it. One small daily thing, one weekly longer thing, one removal. If you can hold these three things, your nervous system will have something to work with. Not enough to fully recover — that takes longer. But enough to stop the free-fall and begin a very gradual return to baseline.', 'Closing commitment: Write your minimal recovery routine. Three lines. Daily anchor, weekly reset, one removal. Keep it somewhere you will see it. |');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('72f2f75a-5b1d-5d16-9b4c-817fa42b4e6f', 'd4c05990-e863-5554-8ce2-71c1146aea1e', 1, 'What is the smallest daily practice you could realistically do every day this week — something under five minutes?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('056a3035-4767-500a-9425-51ddafb757dd', 'd4c05990-e863-5554-8ce2-71c1146aea1e', 2, 'What is one thing in your current routine that is depleting rather than restoring — that you have been treating as self-care but isn''t actually helping?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('a6201e7e-3da0-5a8b-b4a0-31b0036bd44e', 'd4c05990-e863-5554-8ce2-71c1146aea1e', 3, 'What would a realistic weekly reset look like for you — not the ideal version, but the version you would actually do?');
INSERT INTO public.path (id, name, description, tier, pillar, "subMode", "sessionsCount", classifications, "triggerSignals") VALUES ('48e7852c-3431-58a2-89d1-71d73e36823e', 'Navigating Grief and Loss', 'Emotional Well-being  ·  Grief and Loss  ·  Any classification  ·  Requires grief_mode_active \= yes', 'free', 'emotional', 'grief_and_loss', 6, 'Any classification', 'enrollment:onboarding; flag:Requires grief_mode_active \= yes');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('56d8d991-e734-5bea-862a-b4d718caea6f', '48e7852c-3431-58a2-89d1-71d73e36823e', 1, 'What grief actually is — and all the forms it takes', 'Grief is not only what happens when someone dies. Grief is what happens when something that mattered is gone — when a relationship ends, when a life chapter closes, when a dream is surrendered, when a version of yourself or your future disappears. Grief is the appropriate response to real loss. It is not a malfunction. It is love with nowhere left to go. The reason this matters is that many people are grieving without naming it as grief. They feel heavy, flat, disoriented, or inexplicably sad, and they cannot explain why — because the loss they are carrying is not the kind that comes with a funeral or a defined moment of ending. It is the kind that happens quietly, or gradually, or in ways that society does not always validate. If you have come to this path, something has been lost. It may be a person, a relationship, a job, a home, a version of your life, a belief about how things were supposed to go. Whatever it is, it is real. The grief you are carrying about it is real. And you are allowed to be here, taking up space with it. The first thing this path offers is this: permission to call it what it is. You are grieving. That is not weakness. That is what it looks like to have loved something or someone and to be living in the reality of its absence.', 'This week: write down everything you are grieving. Not just the main loss — everything. The things you have not let yourself name yet.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('9d1abebf-cd04-5edc-b483-a96326d1aff4', '56d8d991-e734-5bea-862a-b4d718caea6f', 1, 'What have you lost — not just the obvious thing, but all the layers of it? What else disappeared when that thing disappeared?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('363039a8-a536-5e54-a188-996e6f026a5d', '56d8d991-e734-5bea-862a-b4d718caea6f', 2, 'Have you given yourself permission to call what you''re experiencing grief? If not, what have you been calling it instead?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('dda5219c-be9b-592b-a81c-36dd3299e4bc', '56d8d991-e734-5bea-862a-b4d718caea6f', 3, 'What does the grief feel like in your body right now — where does it live?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('d35b0f46-eb10-5889-9196-3e567273fa8f', '48e7852c-3431-58a2-89d1-71d73e36823e', 2, 'Giving yourself permission to feel it fully', 'There is a particular kind of exhaustion that comes from managing grief rather than feeling it. From keeping it at a controlled distance. From functioning so well on the outside that nobody knows what is happening on the inside. It is the exhaustion of constantly holding something at arm''s length when it wants to come closer. Permission is not the same as collapse. Giving yourself permission to feel grief fully does not mean losing function, being consumed by it, or being unable to move through your day. It means allowing it to move through you — letting the wave come up and pass rather than holding the wall against it indefinitely. Grief that is felt tends to move. Grief that is managed, suppressed, or intellectualized tends to stay. It does not go away when you push it down — it just becomes a permanent part of the background, a kind of low-grade pressure that colors everything without being named. What does it look like to feel it fully? It looks different for everyone. For some people it is crying. For some it is silence. For some it is writing, or walking, or sitting with someone who does not try to fix it. The form matters less than the intention — the intention of allowing rather than managing.', 'This week: schedule fifteen minutes where you allow the grief to be present without trying to resolve or manage it. Write down what comes up afterward — not during, after.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('9849cb1b-9822-5935-a9f0-1a0ac095ea8b', 'd35b0f46-eb10-5889-9196-3e567273fa8f', 1, 'What have you been doing to manage the grief rather than feel it — what strategies have you been using to keep it at a distance?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('2ee17dd0-f853-53fc-b601-8465c869baeb', 'd35b0f46-eb10-5889-9196-3e567273fa8f', 2, 'Is there a time or place where you have allowed yourself to feel it more fully — even briefly? What was that like?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('a3f5852c-cd5c-5b0f-b102-82217f15f8bc', 'd35b0f46-eb10-5889-9196-3e567273fa8f', 3, 'What would it mean to give yourself fifteen minutes this week to simply feel what you feel, without managing it or moving on from it quickly?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('0ea08779-a6b1-5bee-896b-8ea797889ee7', '48e7852c-3431-58a2-89d1-71d73e36823e', 3, 'The non-linear reality of grief — it does not follow a timeline', 'You may have heard of the stages of grief. Denial, anger, bargaining, depression, acceptance. This model has done something helpful and something harmful. It helped people recognize that grief is a real process with real phases. It harmed people by suggesting that grief moves in a predictable, linear, forward direction — that if you are doing it right, you will eventually arrive at acceptance and be done. Grief is not linear. It does not follow a schedule. It does not respect the passage of time in the way most people expect it to. You can feel like you have made real progress and then be ambushed by a song, a smell, a date on the calendar, and feel like you are back at the beginning. You are not back at the beginning. You are encountering grief in a new place, from a new angle, with a new layer visible. The ambush is not failure. It is grief doing what grief does. It circles. It returns. It visits unexpectedly. This is not a sign that something is wrong with you or that you are not healing. It is a sign that what you lost actually mattered. The depth of grief is proportional to the depth of love and connection. What helps is releasing the expectation that you should be further along than you are. There is no further along. There is only where you are, right now, with this particular wave.', 'This week: when grief surfaces unexpectedly, instead of pushing it away, say to yourself: ''This is not a setback. This is grief doing what grief does.'' Notice if that shifts anything.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('07689444-9a81-51dc-ae14-1e2d4b2cc289', '0ea08779-a6b1-5bee-896b-8ea797889ee7', 1, 'Where were you expecting to be in your grief by now — what timeline had you set for yourself?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('2bf337ea-7017-55e5-ad8b-4456fbae0980', '0ea08779-a6b1-5bee-896b-8ea797889ee7', 2, 'Has grief ambushed you unexpectedly recently — returned when you thought you had moved past it? What was that moment?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('5906dfd6-14b8-50de-a84d-e9627b039bfd', '0ea08779-a6b1-5bee-896b-8ea797889ee7', 3, 'What would it mean to release the timeline entirely — to let the grief take as long as it takes without measuring yourself against a schedule?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('0b3e0013-bbf8-55d3-94d7-69813a2c32a5', '48e7852c-3431-58a2-89d1-71d73e36823e', 4, 'What you are allowed to miss', 'There is a strange pressure that sometimes accompanies grief — the sense that you should only be mourning the things that are universally recognized as worth mourning. The person, yes. But what about the way they laughed? The specific version of yourself that existed when they were alive? The life you thought you were going to have? What about grieving the end of a difficult relationship — being allowed to miss the good parts even while knowing the ending was right? What about grieving a job you hated but that gave your days a structure you depended on? What about grieving the version of yourself you were before something happened, even if you would not go back? Grief is not always logically tidy. You can miss things that were also painful. You can grieve losses that other people do not understand or validate. You can mourn things that never fully existed — versions of the future you had imagined, relationships you hoped would become something they didn''t. All of it counts. None of it needs to be justified. The measure of grief is not the social acceptability of the loss. The measure is how much it mattered to you. And you are the only one who can know that.', 'This week: write a list of everything you are allowed to miss. Include the complicated things. The contradictory things. The things no one else would understand.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('6464edf2-0fb1-5b88-9ab2-c095a6dd6bf3', '0b3e0013-bbf8-55d3-94d7-69813a2c32a5', 1, 'What do you miss that you haven''t felt fully allowed to say out loud — the things that feel too complicated or too small to name?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('1561bf09-cfc9-5e21-8a1f-812040de4238', '0b3e0013-bbf8-55d3-94d7-69813a2c32a5', 2, 'Are there parts of what you''ve lost that feel contradictory — things you miss even though the loss was in some ways necessary or right?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('8987bcae-d1ed-5027-9a4a-d36572df6c34', '0b3e0013-bbf8-55d3-94d7-69813a2c32a5', 3, 'What would you want someone to understand about the specific texture of what you have lost — not just the event, but everything that went with it?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('a965b19d-2c85-5b5f-858e-3f2262ba8d3b', '48e7852c-3431-58a2-89d1-71d73e36823e', 5, 'Getting through the hardest days', 'Some days in grief are simply harder than others, and they often do not announce themselves in advance. Anniversaries, milestones, ordinary Tuesdays — grief does not follow a logic you can always anticipate. The hardest days can feel like they come from nowhere, or they can be the days you dreaded in advance and then found to be exactly as difficult as you feared. Getting through hard days in grief is not about moving past them quickly or finding silver linings. It is about surviving them without making them worse, and without judging yourself for how difficult they are. A few things that help: reducing expectations to survival-level for the day — deciding in advance that the goal is to get through, not to function normally. Having one person who knows what day it is and why it is hard. Doing something sensory and present — something that grounds you in your body rather than in your mind. And allowing the day to be what it is without trying to accelerate past it. The hard days are not evidence that you are not healing. They are the texture of grief itself. Every person who has ever lost something significant knows them. Getting through them is enough. It is actually everything.', 'This week: identify your next anticipated hard day — an anniversary, a milestone, a date. Make a plan for it: what will you do, who will you tell, what will you allow yourself not to do.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('4ce9c7fe-cc1f-5d8a-8df8-41e4604c06c2', 'a965b19d-2c85-5b5f-858e-3f2262ba8d3b', 1, 'What do your hardest grief days tend to look and feel like — what makes them different from regular difficult days?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('b7d69ddf-293e-50a9-9d50-10d90a17f72f', 'a965b19d-2c85-5b5f-858e-3f2262ba8d3b', 2, 'What helps you get through those days — even slightly? What makes them worse?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('f274cb8e-aae3-58b4-8359-2af199d309ad', 'a965b19d-2c85-5b5f-858e-3f2262ba8d3b', 3, 'Who is one person who could know when a hard day is happening for you — someone you could reach out to without having to explain everything?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('ba49a088-5f2a-57f5-b88e-298269bba5a2', '48e7852c-3431-58a2-89d1-71d73e36823e', 6, 'When grief and daily life have to coexist', 'Life does not pause for grief. Work continues. Children need to be fed. Responsibilities do not evaporate because you are in the middle of something enormous. One of the most disorienting aspects of grief is being expected — by others and by yourself — to function normally while carrying something that is not normal at all. Coexistence is not the same as recovery. Coexisting with grief means learning to carry it alongside the rest of life rather than waiting for it to resolve before you can reengage. This is not denial. This is how most people actually navigate loss — not by setting grief aside until it is done, but by learning to hold it while also holding everything else. The key is learning which containers can hold it and which ones cannot. Some moments of the day, grief can be present and acknowledged. Others, you need to put it down temporarily — not suppress it, but consciously set it aside so you can do what needs doing — with the intention of returning to it. This is not avoidance. This is the managed rhythm of grief in a life that continues. Give yourself credit for functioning. It costs more than it looks like it costs. The people around you may not see what it takes to get through a day while carrying this. But you know. And it is worth acknowledging.', 'Closing commitment: You made it through this path. Write down one thing you want to carry forward — one permission you are giving yourself about how to grieve in the life you are actually living. |');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('c1268df0-e42d-56ed-ac7f-59b21e2cbdb6', 'ba49a088-5f2a-57f5-b88e-298269bba5a2', 1, 'How are you managing the coexistence of grief and daily function right now — what is working and what is breaking down?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('92bee11f-db18-5620-8488-40775f92957e', 'ba49a088-5f2a-57f5-b88e-298269bba5a2', 2, 'Are there moments in your day when you can allow grief to be present — and moments when you have to set it down? What does that look like?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('c954265a-f422-5c86-a5a8-b98db0ab6456', 'ba49a088-5f2a-57f5-b88e-298269bba5a2', 3, 'What do you wish the people around you understood about what it takes to function right now?');
INSERT INTO public.path (id, name, description, tier, pillar, "subMode", "sessionsCount", classifications, "triggerSignals") VALUES ('c4585c02-be25-5679-a72f-5de048ba9974', 'Boundary Setting Foundations', 'Emotional Well-being  ·  Relationships  ·  Capacity Erosion · Alignment Fracture', 'free', 'emotional', 'relationships', 6, 'Capacity Erosion · Alignment Fracture', 'enrollment:onboarding; flag:None — all users matching classification');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('4d23f27b-fe3a-5e5c-abb0-20b0cce55be8', 'c4585c02-be25-5679-a72f-5de048ba9974', 1, 'Why boundaries are so hard to set and keep', 'Most people know they need better boundaries long before they manage to set them. The knowing is not the problem. The doing is the problem. And the gap between knowing and doing is almost never laziness or lack of willpower. It is something older and deeper than that. Boundaries feel threatening to set because at some earlier point in life, having needs, saying no, or taking up space had real costs. For some people those costs were relational — disapproval, withdrawal, conflict. For others they were more subtle — the sense of not being enough, of being too much, of disrupting a fragile peace that depended on compliance. The nervous system learned from those early experiences. It learned that self-protection is dangerous, that other people''s needs take priority, that keeping the peace is more important than your own wellbeing. These are not irrational conclusions. They were often accurate assessments of specific situations. The problem is that the nervous system tends to generalize — to apply those learned responses to every relationship, long after the original conditions have changed. So when it feels almost impossible to say no to someone — when your body floods with anxiety at the thought of disappointing someone — that is not weakness. That is a very old, very well-practiced protective strategy meeting a situation that no longer requires it. Understanding this is the first step toward changing it.', 'This week: notice one moment where you agree to something you don''t want to do. Don''t change it yet — just notice the moment and what drives it.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('17f8a9ae-7cb6-53ae-a6d6-e4266219d916', '4d23f27b-fe3a-5e5c-abb0-20b0cce55be8', 1, 'When you think about saying no or setting a boundary, what is the specific feeling that comes up — and where do you feel it in your body?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('0bc56862-9c15-56ca-8d7f-5d15731a44e2', '4d23f27b-fe3a-5e5c-abb0-20b0cce55be8', 2, 'Who in your current life do you find it most difficult to hold limits with — and what do you fear would happen if you did?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('d24f68c2-734a-582f-bff2-dc4c380c24ae', '4d23f27b-fe3a-5e5c-abb0-20b0cce55be8', 3, 'Can you trace the difficulty back to an earlier experience — a pattern that taught you that your needs or limits were not safe to express?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('6a305f80-ae2a-52e5-b085-493ecd7b78af', 'c4585c02-be25-5679-a72f-5de048ba9974', 2, 'Identifying where your boundaries have collapsed', 'Before you can rebuild boundaries, you need to see clearly where they have collapsed. This requires honesty — not judgment, but honest inventory. Collapsed boundaries look like many things: consistently taking on more than your share at work because it feels easier than refusing. Saying yes to social commitments you dread attending. Allowing people to speak to you in ways that leave you feeling diminished. Being available at all hours because the discomfort of not responding feels worse than the cost of always responding. Giving advice, money, time, or energy you do not have to give because disappointing someone feels unbearable. None of these things make you a bad person. They make you someone who has learned to put other people''s comfort ahead of your own sustainability. And that pattern, over time, is what creates depletion. It is what creates the exhaustion of carrying more than is yours to carry. It is what makes a life feel like it belongs to everyone else. The inventory is not about assigning blame — to yourself or to others. It is about getting clear-eyed about the current state. You cannot change what you cannot see.', 'This week: write your honest inventory. Three areas where your limits have collapsed. No judgment — just clarity.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('0e93ef98-9b44-53c1-90ff-da9b515710a4', '6a305f80-ae2a-52e5-b085-493ecd7b78af', 1, 'Where in your life do you give more than you have to give — where are you regularly running a deficit?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('c63479eb-10a0-5eb4-82b1-bf20f7a13fd9', '6a305f80-ae2a-52e5-b085-493ecd7b78af', 2, 'In which relationships do you feel most consistently drained, resentful, or taken for granted?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('9b221848-2f6e-5e78-a39b-687e89152dc3', '6a305f80-ae2a-52e5-b085-493ecd7b78af', 3, 'What is the one area where the collapse of your limits is costing you the most right now?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('036d2cd1-ed52-5183-9028-4e24090c41e0', 'c4585c02-be25-5679-a72f-5de048ba9974', 3, 'The difference between a boundary and a wall', 'A boundary is not the same as a wall. This distinction matters because many people who struggle with boundaries swing between two extremes: no limits at all, or complete shutdown and withdrawal. Neither of these is actually what a healthy boundary looks like. A wall keeps everyone out. It is a protective structure that says: I have been so hurt, so depleted, so taken from that I cannot let anyone close enough to risk it happening again. Walls create safety through isolation. They protect you from harm by preventing connection. A boundary is different. A boundary says: I can be in relationship with you and I have limits. I can love you and not sacrifice myself for you. I can give and there are things I will not give. I can be present and I will leave when I need to. Boundaries are not walls because they do not require cutting people off. They require honesty about what you can and cannot give. They require the willingness to name your limits even when it is uncomfortable. And they require the ability to hold those limits with warmth — not as rejection, but as the conditions that make genuine relationship possible. The goal is not distance. The goal is sustainable presence.', 'This week: practice saying one true thing about what you need or cannot do — with warmth rather than withdrawal. Notice the difference.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('7d85cddb-a5ec-57f7-b641-3093594bf6b8', '036d2cd1-ed52-5183-9028-4e24090c41e0', 1, 'Do you tend toward no limits at all, or toward walls and shutdown? Which pattern is more familiar for you?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('a96cf271-cf56-55bd-a282-7438d576879f', '036d2cd1-ed52-5183-9028-4e24090c41e0', 2, 'Think of a relationship where you feel you can be fully present without losing yourself. What makes that relationship different?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('8b5b2a72-aac3-5ba6-b42a-9cbe255109c9', '036d2cd1-ed52-5183-9028-4e24090c41e0', 3, 'What would it look like to hold a limit with someone important to you while still remaining warm and connected?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('5df8d773-cb53-5d7d-bc68-bf8588e278ad', 'c4585c02-be25-5679-a72f-5de048ba9974', 4, 'How to say no without guilt destroying you', 'The word no is one of the shortest sentences in the English language. It is also one of the hardest to say and mean simultaneously. Most people can say no — what they cannot do is say it without the guilt that follows making the no feel worse than the yes would have been. Guilt about saying no is almost always rooted in a belief about what saying no means. It means I am selfish. It means I do not care enough. It means I am failing someone who needs me. It means the relationship is at risk. These beliefs are almost never examined — they just activate, automatically, the moment the no crosses your lips. What actually happens when you say no to a reasonable request in a healthy relationship? Usually: the person is briefly disappointed and adjusts. The relationship continues. Nothing catastrophic occurs. The feared consequence — the withdrawal of love or approval, the conflict, the judgment — either does not materialize or is survivable. The guilt does not last as long as you think it will. And the resentment of a yes you did not mean lasts much longer. This is worth sitting with: the discomfort of the no, measured against the cost of the yes. Most of the time, the no is the kinder choice — for both people.', 'This week: say no to one thing you would normally say yes to despite not wanting to. Let the guilt be there without acting on it. Notice how long it actually lasts.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('01bd1b49-ba0a-5914-a1c5-481638ada50b', '5df8d773-cb53-5d7d-bc68-bf8588e278ad', 1, 'What is your specific guilt narrative when you say no — what do you tell yourself it means about you?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('23760b46-0a0d-5aac-a944-8b66882eb1ce', '5df8d773-cb53-5d7d-bc68-bf8588e278ad', 2, 'Think of a time you said no and the feared consequence did not happen — what did that experience teach you?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('27186d4c-a4f9-5081-8f7b-d1e186ed98cd', '5df8d773-cb53-5d7d-bc68-bf8588e278ad', 3, 'What is the difference, for you, between guilt that is meaningful information and guilt that is just an old learned response?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('2102c322-9ac4-5be4-93f5-4f27947477cd', 'c4585c02-be25-5679-a72f-5de048ba9974', 5, 'One boundary to practice this week', 'Everything in this path has been building toward this: identifying one specific limit and practicing holding it this week. Not a complete overhaul of every relationship. Not a boundary-setting campaign. One thing. The most effective practice boundaries are small, specific, and realistic. Not ''I will stop letting people take advantage of me'' — that is too broad to be actionable. Instead: ''I will not respond to work messages after 7pm this week.'' ''I will tell my mother I cannot talk on Sunday afternoons.'' ''I will say no to the one request I know is coming that I have been dreading.'' Small and specific matters because a limit you actually hold is infinitely more powerful than a limit you set in theory and abandon in practice. Your nervous system needs evidence that holding a limit is survivable. One held limit, one time, starts to build that evidence. It is the beginning of a new pattern — not the completion of one. Choose something real. Something that actually matters to you. Something with a genuine cost if you don''t hold it. And then hold it, even if it is uncomfortable, even if the guilt comes, even if the other person is disappointed. Notice what happens. Notice that you are still standing.', 'This week: set and hold your one practice boundary. Tell one person you are doing it. Report back to yourself on how it went.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('f1cb694b-e526-53e6-941f-2980660f0aaa', '2102c322-9ac4-5be4-93f5-4f27947477cd', 1, 'What is the one boundary you most need to practice this week — specific enough that you could describe exactly what it looks like in action?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('abdc8927-a775-5f0c-8b8c-8dddfb34d767', '2102c322-9ac4-5be4-93f5-4f27947477cd', 2, 'What is the most likely obstacle — internal or external — to holding it?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('404944cc-2bf1-5f49-9904-3594bc1194e2', '2102c322-9ac4-5be4-93f5-4f27947477cd', 3, 'Who could you tell about this practice, so that someone knows and can ask how it went?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('d73340df-4181-59d8-998e-45de90add882', 'c4585c02-be25-5679-a72f-5de048ba9974', 6, 'What happens when people push back', 'Setting a limit is one thing. Holding it when someone pushes back is another. And pushback is normal — not universal, but common enough that you should expect it and be prepared for it. Pushback does not always look like anger. Sometimes it looks like guilt-induction: ''I can''t believe you would do this to me.'' Sometimes it looks like minimizing: ''You''re being so sensitive.'' Sometimes it looks like persistent re-asking, as if asking enough times will change your answer. Sometimes it looks like silence and withdrawal. All of these are responses to the fact that your no disrupts a dynamic the other person has relied on. That disruption is uncomfortable for them. It does not make you wrong. A person who genuinely respects you will adjust after an initial reaction. A person who cannot tolerate your limits at all is telling you something important about the relationship. Holding the limit when there is pushback requires two things: staying calm enough to remain clear rather than reactive, and having something to say that is neither aggressive nor apologetic. Something like: ''I understand this is disappointing. My answer is still no.'' That sentence. That one sentence. Said calmly. Said with warmth if possible. And then not elaborated on further. You do not need to justify a limit. You do not need to convince the other person it is valid. You need to hold it.', 'Closing commitment: Write down your response to pushback. One sentence. Practice it out loud. Know what you will say before you need to say it. |');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('8e7d94ad-ce32-5d3d-9154-8e8e31ced2d7', 'd73340df-4181-59d8-998e-45de90add882', 1, 'What kind of pushback do you find hardest to hold a limit against — anger, guilt-induction, minimizing, withdrawal?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('f553337d-2d99-5ca6-9b6b-afe5d7d89046', 'd73340df-4181-59d8-998e-45de90add882', 2, 'What do you typically do when someone pushes back — and how does it tend to end up?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('c7bd409e-0a61-5914-9a59-d81e3e592340', 'd73340df-4181-59d8-998e-45de90add882', 3, 'What would you need to believe, or feel, to hold your position calmly when someone challenges your no?');
INSERT INTO public.path (id, name, description, tier, pillar, "subMode", "sessionsCount", classifications, "triggerSignals") VALUES ('7d90ca8d-4d1a-5e37-a287-3f9ff65b8b11', 'Clarity and Direction', 'Professional  ·  General Professional  ·  Performance Stagnation · Alignment Fracture', 'free', 'professional', 'general_professional', 5, 'Performance Stagnation · Alignment Fracture', 'enrollment:onboarding; flag:None — all users matching classification');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('570166c5-9ca2-5261-bc1c-a17ee5a63eee', '7d90ca8d-4d1a-5e37-a287-3f9ff65b8b11', 1, 'Why you feel stuck — naming it clearly', 'Stuck is one of those words that covers a lot of ground. When people say they feel stuck, they usually mean one of several very different things — and knowing which one actually applies to you changes completely what needs to happen next. Some people are stuck because they do not know what they want. The direction is genuinely unclear, and forward motion feels impossible because there is no destination. This is a clarity problem. Some people know what they want but cannot make themselves move toward it. The desire is real, the vision exists, but the action does not follow. This is usually a fear problem, or a belief problem — something beneath the surface that makes the gap between intention and action feel unbridgeable. Some people are moving — working hard, staying busy, producing — but feel stuck because they are moving in the wrong direction. The effort is real but the destination is someone else''s idea of what their life should look like. This is an alignment problem. And some people are simply depleted. They would move if they had something to move with, but the tank is empty. This is a capacity problem, not a clarity problem, and the solution is different. Before you can get unstuck, you need to know what kind of stuck you actually are.', 'This week: write your honest answer to this question: What is actually in the way of moving forward? Not the surface answer — the real one.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('644a29bf-817a-5ec7-83aa-686e87ba1e65', '570166c5-9ca2-5261-bc1c-a17ee5a63eee', 1, 'When you say you feel stuck, which of the four types resonates most — clarity, fear, alignment, or depletion?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('63a1cf08-c3c9-5961-9102-ff99bab3929d', '570166c5-9ca2-5261-bc1c-a17ee5a63eee', 2, 'How long have you felt this way — and what changed, or failed to change, that created the stuck feeling?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('cadd577b-9e74-5c08-9664-fd3c1a37de12', '570166c5-9ca2-5261-bc1c-a17ee5a63eee', 3, 'If you are being completely honest with yourself, do you know what you want and are avoiding it — or do you genuinely not know?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('479f1a2d-9b54-5c03-8252-93bfdffea7c9', '7d90ca8d-4d1a-5e37-a287-3f9ff65b8b11', 2, 'The difference between unclear goals and wrong goals', 'There is a crucial distinction between not knowing what you want and knowing what you want but sensing it is not actually right for you. These feel similar — both produce paralysis, both produce the stuck feeling — but they have very different solutions. Unclear goals respond to exploration, to asking better questions, to gathering more information about yourself and what matters to you. Wrong goals require something more difficult: the willingness to name that the goal you have been pursuing — the one that looks impressive, the one other people expect, the one you have been working toward for years — is not actually yours. Wrong goals are exhausting in a particular way. They produce effort without energy — the grinding sensation of working toward something that never quite generates the motivation it should. They produce the nagging sense that even if you achieved this thing, it would not feel like you thought it would. They often have their origins in someone else''s vision for your life that you absorbed so early and so completely that it became indistinguishable from your own. Not every goal that is hard to reach is a wrong goal. Hard and wrong are not the same thing. But a goal that consistently fails to generate any intrinsic pull — that you can only work toward through discipline rather than through genuine desire — is worth examining honestly.', 'This week: write two lists. List 1: what you think you should want. List 2: what you actually notice yourself drawn toward. Compare them.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('cf8cd2b6-157d-5add-9eef-25ab97249236', '479f1a2d-9b54-5c03-8252-93bfdffea7c9', 1, 'Is the goal you are currently working toward — or stuck in relation to — one you chose, or one you absorbed from somewhere else?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('f29bdc4c-9c35-5890-8b27-df1a80ab0a28', '479f1a2d-9b54-5c03-8252-93bfdffea7c9', 2, 'When you imagine achieving it, what does the feeling in your body say? Excited? Relieved? Flat? Those responses are data.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('7c5e343c-3a64-5402-8bd3-54f7b7ed5e2b', '479f1a2d-9b54-5c03-8252-93bfdffea7c9', 3, 'If you could do anything with this next chapter of your professional life and no one would judge you for it, what would it be?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('9fde8093-f2db-5889-8174-cbee93931f1a', '7d90ca8d-4d1a-5e37-a287-3f9ff65b8b11', 3, 'Values as a compass for professional decisions', 'When direction is unclear, values cut through the noise. Not values in the abstract, motivational-poster sense — but values in the specific, behavioral sense. The things that, when absent from your work, drain the energy out of everything. The things that, when present, make hard work feel worth it. Values are identifiable through pattern recognition. Look at the moments in your professional life when you felt most alive, most engaged, most like yourself. Not necessarily the easiest moments — sometimes the most values-aligned work is also the hardest. But the moments when you knew you were doing something that mattered, in a way that fit who you actually are. Now look at the moments of the deepest professional dissatisfaction. Not the frustration of something being difficult — the particular hollow sensation of work that does not fit. What was missing? What was being required of you that conflicted with something important? The gap between those two categories tells you something precise about your values. And your values, once identified, function as a compass — they do not tell you exactly where to go, but they tell you which direction is toward and which direction is away.', 'This week: identify your top three professional values. Write one sentence for each explaining why it matters to you specifically — not generically, but in your own story.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('1605cc78-2d9a-5b2f-9cc1-56c9ca7e7597', '9fde8093-f2db-5889-8174-cbee93931f1a', 1, 'Think of a professional moment when you felt most genuinely engaged and alive. What specifically was present in that moment that made it feel that way?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('93656b5e-14de-5d5d-a0c2-5e4007806efb', '9fde8093-f2db-5889-8174-cbee93931f1a', 2, 'Think of a professional moment of deepest dissatisfaction — not difficulty, but wrongness. What was missing or conflicting?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('1d769cbc-14b7-5af3-b17d-a4f7e74017ba', '9fde8093-f2db-5889-8174-cbee93931f1a', 3, 'Based on those two experiences, what are two or three values that seem non-negotiable for your work to feel meaningful?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('89e850b6-3fb0-5915-8a26-b4299572353e', '7d90ca8d-4d1a-5e37-a287-3f9ff65b8b11', 4, 'One thing to clarify this week', 'Clarity does not arrive all at once. It accumulates, one honest question answered at a time. Waiting for complete clarity before taking any action is one of the ways intelligent people stay stuck for years. The alternative is incremental clarity — identifying the single most important question that, if answered, would make the next step visible. Not all the steps. Just the next one. And answering that question with whatever imperfect information is currently available. The question might be: what do I actually want from my career, as distinct from what I have been told to want? It might be: am I in the wrong role, the wrong organization, or the wrong field? It might be: what is the specific thing I am afraid will happen if I try to change direction? It might be: what would I do if I already trusted myself to do it? Answering one of these questions well — not perfectly, but honestly — moves you forward. Trying to answer all of them simultaneously moves you nowhere.', 'This week: write your one most important question. Then write your honest best current answer to it — not the definitive answer, just your best current one.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('130eea0a-9fd7-556e-9415-22826a626b8a', '89e850b6-3fb0-5915-8a26-b4299572353e', 1, 'What is the single most important question about your professional direction that, if answered, would make the next step clearer?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('1ec194c4-b588-5b05-b894-8c55360fe35b', '89e850b6-3fb0-5915-8a26-b4299572353e', 2, 'What information, or what honest conversation with yourself, do you need to begin answering it?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('d32ae24d-ad51-5e48-a754-fcecbe780373', '89e850b6-3fb0-5915-8a26-b4299572353e', 3, 'What small action would you take this week if you had already answered it?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('888789b4-cf13-5b91-b89c-40ad1a06ea65', '7d90ca8d-4d1a-5e37-a287-3f9ff65b8b11', 5, 'What momentum looks like at the start', 'Here is what momentum does not look like at the start: it does not look like certainty. It does not look like confidence. It does not look like knowing exactly where you are going and having a clear path to get there. That description is momentum in the middle, or momentum at the end. Momentum at the start looks different. Momentum at the start looks like making one decision, even with incomplete information. It looks like taking one step in a direction that feels more right than wrong, without requiring that direction to be proven before you move. It looks like reducing the size of the next action until it is small enough that the fear of taking it is smaller than the cost of staying still. The first steps in a new direction are almost always tentative. They are supposed to be tentative. You are gathering information. You are testing hypotheses about yourself and what fits you. You are building evidence — slowly, one small action at a time — that forward motion is possible and survivable. You do not need a plan. You need a next step. Just the next one.', 'Closing commitment: Name your next step. Name the day you will take it. Tell one person. |');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('a1fe2cd8-213b-5a48-9fe9-fbba1f559f15', '888789b4-cf13-5b91-b89c-40ad1a06ea65', 1, 'What is the smallest possible next step in the direction that feels most right — small enough that the fear of it is manageable?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('008cd650-29fe-53ba-844c-9335d7fdad48', '888789b4-cf13-5b91-b89c-40ad1a06ea65', 2, 'What would you need to believe about yourself to take that step without requiring certainty first?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('b40681d0-4c54-5666-80e5-f533fc522176', '888789b4-cf13-5b91-b89c-40ad1a06ea65', 3, 'When specifically will you take it — not ''soon,'' but which day this week?');
INSERT INTO public.path (id, name, description, tier, pillar, "subMode", "sessionsCount", classifications, "triggerSignals") VALUES ('14d5a7db-6c76-5fda-9d37-a4817e91c622', 'Building Professional Momentum', 'Professional  ·  General Professional  ·  Performance Stagnation · Building Momentum', 'free', 'professional', 'general_professional', 6, 'Performance Stagnation · Building Momentum', 'enrollment:onboarding; flag:None — all users matching classification');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('12685082-7219-5647-8636-9c8fd6da3fbe', '14d5a7db-6c76-5fda-9d37-a4817e91c622', 1, 'The anatomy of a stalled professional season', 'Professional stagnation is not always dramatic. It does not always look like a crisis or a failure. Often it looks like a quiet erosion — the gradual loss of the forward feeling, the sense of movement and progress that used to make work feel worthwhile. One day you look up and realize you cannot remember the last time a professional goal genuinely excited you. Stalled seasons happen for different reasons in different people. Sometimes they follow a significant effort — a project, a push, an ambitious period — and the crash afterward is simply the system recalibrating. Sometimes they are the result of the wrong goal: working hard in a direction that was never quite right, until the momentum simply runs out. Sometimes they are circumstantial — a change in leadership, a pandemic, a life event that disrupted the rhythm and never quite restarted. And sometimes a stalled season is the transition period between who you were professionally and who you are becoming. Not failure. Just the pause that precedes a significant shift. Whatever the cause of yours, naming it accurately matters — because the response to depletion is different from the response to wrong direction, which is different from the response to circumstance. The first question is always: what actually happened here?', 'This week: write the honest answer to what happened. Not the sanitized version — the real one. What caused the stall?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('6c2e2dcc-3fd0-5739-920c-c52a7b493034', '12685082-7219-5647-8636-9c8fd6da3fbe', 1, 'When did you last feel genuine forward momentum professionally — what was present then that is not present now?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('734ea8c3-bcd3-5881-a642-a12561c4db9c', '12685082-7219-5647-8636-9c8fd6da3fbe', 2, 'Looking at your stalled season honestly, what do you think actually happened — what caused the stall?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('8607de8d-48c4-55f6-a38d-f2f76f1f3e71', '12685082-7219-5647-8636-9c8fd6da3fbe', 3, 'Is this a depletion problem, a direction problem, a circumstance problem, or a transition period? What feels most true?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('50f57ab9-deb4-56ce-b0d0-99f1472f8601', '14d5a7db-6c76-5fda-9d37-a4817e91c622', 2, 'Small wins as a momentum strategy', 'Momentum is not built by waiting until you have enough motivation to take a large action. Momentum is built by taking small actions and allowing the accumulated evidence of those actions to generate motivation. This reverses the sequence most people assume. Most people believe: I need to feel motivated, then I will take action, then I will have momentum. The actual sequence is almost the opposite: I take a small action, that action produces a small result, that result creates a small amount of evidence that forward motion is possible, and that evidence generates a small amount of motivation for the next action. Small wins work not because they are dramatic — they are not. They work because they interrupt the narrative of stagnation. Every day that you do not move forward produces more evidence that forward motion is impossible. Every small action you take, no matter how insignificant it seems, produces a counter-data point. You did something. It worked. That matters. The specific content of the small win is less important than its consistency. A tiny action done every day for a week creates more momentum than a large action done once. The nervous system learns from repetition, not intensity.', 'This week: identify your daily small action. Something that takes under 15 minutes. Do it seven days in a row. Log it.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('91e850ea-0277-5893-8d57-a9d6172624f8', '50f57ab9-deb4-56ce-b0d0-99f1472f8601', 1, 'What is the smallest professional action you could take today that would feel like forward movement — no matter how minor?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('ea8cc729-4cdd-5550-a62b-7ba59fdedb77', '50f57ab9-deb4-56ce-b0d0-99f1472f8601', 2, 'What has stopped you from taking that kind of small action consistently in the past?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('986e1f4c-2e91-54f2-9f80-7a9ea0977f8c', '50f57ab9-deb4-56ce-b0d0-99f1472f8601', 3, 'If you committed to one very small professional action every day for the next seven days, what would you choose?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('16fca5e5-7c08-51c3-819a-e48831be24fa', '14d5a7db-6c76-5fda-9d37-a4817e91c622', 3, 'Identifying the highest-leverage action', 'Not all actions move the needle equally. One of the reasons people stay stuck despite being busy is that they are expending significant effort on low-leverage activities — things that feel productive without actually advancing anything meaningful. The goal of this session is to identify where the real leverage lives. High-leverage actions are the ones that, if done, make multiple other things easier or possible. They are often the ones you have been avoiding — because they require clarity about what actually matters, because they carry some risk of failure or judgment, because they feel more exposed than the busy work that surrounds them. In a professional stagnation, the highest-leverage action is often the one that feels most uncomfortable. The conversation you have been avoiding. The decision you have been postponing. The ask you have been afraid to make. The piece of work that would require you to put something real on the line. Doing the lowest-risk, most comfortable version of staying busy is not the same as building momentum. At some point, forward motion requires doing the uncomfortable thing.', 'This week: identify your highest-leverage action. Take one step toward it — not the whole action, just one step. Notice the resistance and take the step anyway.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('5bc9f7de-fbc7-5cef-b83f-c1373aac0cb1', '16fca5e5-7c08-51c3-819a-e48831be24fa', 1, 'What is the one professional action that, if you actually did it, would create the most meaningful forward movement right now?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('7918315f-3fa8-508f-aa94-4607f2fbd62b', '16fca5e5-7c08-51c3-819a-e48831be24fa', 2, 'What has stopped you from taking that action — be specific about the actual obstacle?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('89d3fd21-4f41-55ce-b43e-29e4f399fbee', '16fca5e5-7c08-51c3-819a-e48831be24fa', 3, 'What would you need to believe or feel to take it this week, even imperfectly?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('eda7d7b2-dfe5-5f62-aea4-bc2d974b310c', '14d5a7db-6c76-5fda-9d37-a4817e91c622', 4, 'Building a simple accountability structure', 'Accountability is not about having someone watching over you to make sure you comply. Accountability, in its useful form, is about creating conditions where the cost of not following through is high enough to motivate action, and the cost of following through is lower than you think. The simplest accountability structure that works is this: tell one person what you are going to do and when you are going to do it. Not a goal — a specific action with a specific deadline. And then tell them after you have done it. This structure works because social commitment activates a different part of the brain than private intention. When you tell someone what you are going to do, the discomfort of not doing it is real and immediate. When you only tell yourself, the renegotiation of your commitment happens privately, with no social cost, and it happens easily. The person you choose matters somewhat. They should be someone who will actually ask. Someone who will not let you off the hook with vague updates. Someone who cares enough about your growth to be mildly persistent. This does not need to be a formal accountability partner or coach — it can be a friend who asks a direct question and expects a direct answer.', 'This week: tell one person one specific thing you will do by one specific date. Then do it.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('0cad3697-e917-520e-ba4a-bad038aa29e9', 'eda7d7b2-dfe5-5f62-aea4-bc2d974b310c', 1, 'Who in your life would make the best accountability partner for your professional goals right now — someone specific?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('d7e97b71-a962-515e-afee-53fc12c76527', 'eda7d7b2-dfe5-5f62-aea4-bc2d974b310c', 2, 'What is the specific action you would commit to, and what is the specific deadline you would set?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('d8c47e61-7332-5772-9636-a9e3bf27032c', 'eda7d7b2-dfe5-5f62-aea4-bc2d974b310c', 3, 'What happens internally when you make a commitment to yourself versus when you make it to another person — what is the difference?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('2c666a80-e67e-584c-bd5c-68ce034015f2', '14d5a7db-6c76-5fda-9d37-a4817e91c622', 5, 'What consistency actually looks like in practice', 'Consistency is not doing the same thing perfectly every single day without exception. That description is perfectionism, not consistency. Consistency is doing something reliably enough that the pattern holds — that the accumulation continues even when individual days are messy. Real consistency looks like this: you have a practice or a commitment, and you hold it most of the time, and when you miss a day you return to it the following day without making the miss mean something catastrophic about your ability to sustain effort. The return is the skill. The miss is not the failure. The failure is not returning. Most people quit consistent practices not because they missed a day but because they decided that missing a day meant they were not the kind of person who could maintain consistency. The miss activated a story — I always do this, I can''t sustain anything, I knew I would fail at this too — and the story became more powerful than the practice. The professional momentum you are building requires you to be better at returning than you are at never missing. Because you will miss. Everyone does. What distinguishes people who build momentum from those who stay stuck is not that they never falter — it is that they come back.', 'This week: when you miss your daily action (not if), practice the return without the story. Just pick back up. Notice that you can.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('85e506ad-60fb-51a7-979e-7a3829d00e36', '2c666a80-e67e-584c-bd5c-68ce034015f2', 1, 'What is your pattern when you miss a day or fall off a commitment — what story do you tell yourself, and what do you do next?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('c170bb39-40f5-51d9-90f8-96bd30722203', '2c666a80-e67e-584c-bd5c-68ce034015f2', 2, 'What would it look like to have a return practice — a specific response to a miss that brings you back without drama?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('4aa474d6-579a-5f20-810f-5ea70685a2d2', '2c666a80-e67e-584c-bd5c-68ce034015f2', 3, 'What is one professional commitment you want to build consistency around over the next 30 days?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('35a71f5e-ab21-567e-bb55-4921843eea3f', '14d5a7db-6c76-5fda-9d37-a4817e91c622', 6, 'Measuring progress without perfection', 'Stalled seasons distort your perception of how far you have actually come. When you are in the middle of building momentum, it often does not feel like progress — it feels like inadequate progress, like too slow, like not enough. The comparison is always to where you think you should be, not to where you actually started. Useful measurement compares where you are now to where you were, not to some ideal endpoint. It asks: what is different today compared to three weeks ago? What have I actually done that I would not have done then? What feels slightly more possible that felt impossible at the beginning of this path? Progress in momentum-building is often felt before it is seen. You notice that you are slightly less avoidant of the high-leverage actions. You notice that the resistance to the daily commitment is slightly smaller. You notice that you are thinking more often about what is possible rather than rehearsing what is impossible. These internal shifts are real progress, even when the external results are not yet visible. Measure honestly. Compare backward, not upward. And give yourself credit for what you have actually done — not what remains undone, but what happened.', 'Closing commitment: Write your honest assessment of the progress you have made. Then write the one thing you will continue past this path. | | BATCH 1 COMPLETE — PATHS 4 THROUGH 8 | | :---: | *This batch contains complete session content for the following 5 paths:* Path 4 — Nervous System Basics (5 sessions · Free · Capacity Erosion) Path 5 — Navigating Grief and Loss (6 sessions · Free · grief_mode_active required) Path 6 — Boundary Setting Foundations (6 sessions · Free · Capacity Erosion · Alignment Fracture) Path 7 — Clarity and Direction (5 sessions · Free · Performance Stagnation · Alignment Fracture) Path 8 — Building Professional Momentum (6 sessions · Free · Performance Stagnation · Building Momentum) Total sessions in this batch: 28 Total sessions across Paths 1–8: 66 Remaining: Paths 9–18 (Batch 2: Paths 9–13 · Batch 3: Paths 14–18) | Uncloud360™  ·  MVP Path Content Batch 1  ·  Paths 4–8 Proven Under Pressure  ·  Dr. Sam  ·  April 2026  ·  Confidential | | :---:');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('cca4a54a-2a52-5693-8926-dcce1f5b9a59', '35a71f5e-ab21-567e-bb55-4921843eea3f', 1, 'Compared to where you were at the beginning of this path, what has actually changed — in your actions, your mindset, or your relationship to your professional life?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('8a381aef-f857-5318-ae8e-49ca1ad34112', '35a71f5e-ab21-567e-bb55-4921843eea3f', 2, 'What small thing have you done in the past few weeks that felt like genuine forward movement, even if it was minor?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('e2b31764-e44c-5ef2-8f69-3ca9306a7c1f', '35a71f5e-ab21-567e-bb55-4921843eea3f', 3, 'What does meaningful progress look like for you over the next 30 days — measured against where you started, not against an ideal?');
INSERT INTO public.path (id, name, description, tier, pillar, "subMode", "sessionsCount", classifications, "triggerSignals") VALUES ('f1b841e9-a4bf-51d9-b598-0514d6668d0d', 'Understanding Your Emotional Patterns', 'Emotional Well-being  ·  General Emotional  ·  All classifications', 'pro', 'emotional', 'general_emotional', 7, 'All classifications', 'enrollment:onboarding; flag:None — all users matching classification');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('421169db-39a6-5d97-ab03-cbc0c1d30969', 'f1b841e9-a4bf-51d9-b598-0514d6668d0d', 1, 'Mapping your emotional triggers', 'A trigger is not just something that upsets you. A trigger is a stimulus that activates a disproportionate emotional response — a reaction that is bigger, faster, or more intense than the situation seems to warrant. Understanding your triggers is not about becoming less sensitive. It is about understanding why certain things land the way they do for you specifically. Triggers are almost always connected to something older than the current situation. The coworker''s offhand comment that devastated you for two days is not really about the comment. The argument that spiraled into something enormous over something small is not really about the small thing. Beneath the surface trigger is usually a wound — an old experience, a long-standing belief, a pattern of being treated in a certain way — that the current situation is touching. Mapping your triggers means getting curious about the pattern rather than just experiencing it. What are the themes? What kinds of situations consistently produce the strongest reactions? What does the reaction feel like in your body, and how quickly does it arrive? What story does it activate about yourself or about other people? You cannot stop yourself from being triggered. But you can build enough self-awareness to recognize when it is happening — which creates the possibility of a response rather than just a reaction.', 'This week: when you notice a strong emotional reaction, pause and ask — what is this actually about? Write down what you find.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('4f176730-a62d-56d3-b038-4170f087b002', '421169db-39a6-5d97-ab03-cbc0c1d30969', 1, 'What are two or three situations or types of interactions that consistently produce the strongest emotional reactions in you?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('4d1ec4ba-7f93-544b-bda7-bf4c365ddb3f', '421169db-39a6-5d97-ab03-cbc0c1d30969', 2, 'When you get triggered, what is the story it activates — what does the situation seem to mean about you or about others?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('3131a057-0909-5d23-8d2b-e9f5bc93d713', '421169db-39a6-5d97-ab03-cbc0c1d30969', 3, 'Where does the trigger live in your body, and how quickly does the reaction arrive — is there any space between the stimulus and the response?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('df03e685-77e1-5b1e-b9f2-a6c74056ae31', 'f1b841e9-a4bf-51d9-b598-0514d6668d0d', 2, 'The stories you tell yourself under pressure', 'Under pressure, the brain defaults to its most practiced narratives. These are not always accurate. They are efficient — the mind reaches for familiar interpretations quickly, particularly when resources are depleted and there is no bandwidth for nuanced thinking. The most common under-pressure narratives follow recognizable patterns. There is catastrophizing — the automatic assumption that the worst will happen, that a setback is a catastrophe, that a difficulty is a sign of fundamental failure. There is personalizing — interpreting neutral events as comments on your worth or competence. There is mind-reading — assuming you know what others are thinking, usually something negative about you. And there is filtering — focusing exclusively on the negative data while discounting everything that contradicts it. These narratives are not character flaws. They are cognitive habits, usually formed in circumstances where a certain kind of alertness was adaptive. The problem is that they tend to persist past the conditions that formed them, shaping how you interpret experience in ways that increase suffering rather than reduce it. The first step is not to eliminate these narratives — that is neither possible nor necessary. The first step is to be able to see them as narratives rather than as facts. When you are in the middle of a story, it feels like reality. When you can observe that you are in a story, it creates space. That space is where change becomes possible.', 'This week: catch yourself in a story. Write it down. Then write one sentence that questions whether the story is actually true.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('f65fae4f-945d-5154-bbce-131e304fa522', 'df03e685-77e1-5b1e-b9f2-a6c74056ae31', 1, 'What is your most common under-pressure narrative — the story your brain defaults to when things get hard?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('e367b76f-3735-5803-8664-7dccad33b950', 'df03e685-77e1-5b1e-b9f2-a6c74056ae31', 2, 'Where did this narrative come from — is there an early experience or pattern that it maps onto?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('a28189de-e10d-55b5-8c3f-62bc2c884183', 'df03e685-77e1-5b1e-b9f2-a6c74056ae31', 3, 'What would you see differently about a recent difficult situation if this narrative were not running?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('330a17a5-162a-5a5e-b34b-886723e69258', 'f1b841e9-a4bf-51d9-b598-0514d6668d0d', 3, 'Emotional reactivity versus emotional response', 'There is a crucial difference between an emotional reaction and an emotional response, and it is not whether the emotion is strong. It is whether there is any space — any at all — between the stimulus and what you do with it. Reactivity is instantaneous. Something happens, and the emotion takes over before any conscious processing occurs. The words come out before you decide to say them. The tone shifts before you notice it shifting. The behavior happens and only afterward do you register what occurred. Reactivity is fast, automatic, and tends to create consequences that then need managing. Response is not the absence of emotion — it is emotion plus a moment of choice. Even a very brief moment. The feeling is still real and present, but there is just enough space between the feeling and the action for something other than pure reaction to occur. That space is what allows you to choose how to move through the emotion rather than letting the emotion move you. The space does not come from suppressing or overriding the emotion. It comes from developing a relationship with your emotional experience — enough familiarity with what it feels like that you can recognize it in real time, before the automatic behavior has already happened. This is what emotional intelligence actually is: not the absence of strong feeling, but the ability to feel strongly and still have a choice.', 'This week: identify one pattern of reactivity and practice inserting one breath before responding. Just one breath.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('9ea97fa1-6dac-5fb6-ae50-7e81d916b97f', '330a17a5-162a-5a5e-b34b-886723e69258', 1, 'Think of a recent situation where you were reactive rather than responsive. What was the cost of the reaction?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('dcd77e62-16f4-5f50-8b8a-5b2515620a61', '330a17a5-162a-5a5e-b34b-886723e69258', 2, 'What would it have looked like to respond rather than react — what would have been different?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('1db1acb8-5dea-5186-a026-ec219ddc5752', '330a17a5-162a-5a5e-b34b-886723e69258', 3, 'What helps you create space between stimulus and response — even briefly? What makes that space harder to find?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('7961ae95-a787-56ae-9aec-1369fc69d5f4', 'f1b841e9-a4bf-51d9-b598-0514d6668d0d', 4, 'Your historical patterns — what shows up when things get hard', 'Each of us carries a small set of patterns that reliably emerge under pressure — ways of being that are so practiced they have become almost automatic. Understanding yours is not about assigning blame to your past or pathologizing your responses. It is about seeing clearly the patterns that are running below the surface so that you have some agency in relation to them. Some people become controlling under pressure — managing every variable, micromanaging others, needing to be certain in order to tolerate uncertainty. Some people become withdrawn — going quiet, becoming unavailable, creating distance to manage the overwhelm. Some people become appeasing — minimizing their own needs, working to smooth everyone else''s feelings, making themselves smaller to avoid conflict. Some become aggressive — using intensity or conflict to create distance or control. These patterns are not random. They were learned responses to specific conditions, and they probably served a real purpose at some point. The question is not whether the pattern was understandable. The question is whether it is still serving you now, in these circumstances, in this relationship, in this moment. Naming the pattern is the beginning. You cannot interrupt something you cannot see.', 'This week: watch for your pattern. When it shows up, name it internally: ''There it is.'' Don''t try to stop it yet — just see it.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('9d26649b-f9e2-5124-81a6-966ecbb98882', '7961ae95-a787-56ae-9aec-1369fc69d5f4', 1, 'What is your most reliable under-pressure pattern — the behavior that tends to show up consistently when things get difficult?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('54f3d1be-943e-5999-bd9f-e13c9e4a93b3', '7961ae95-a787-56ae-9aec-1369fc69d5f4', 2, 'Where did you learn this pattern — what circumstances taught you that this was an effective response?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('89953010-0a51-56a4-bc33-563df767665c', '7961ae95-a787-56ae-9aec-1369fc69d5f4', 3, 'In a recent situation, how did this pattern show up — and what was the cost of it in that specific case?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('8eff9512-def9-51a8-8e89-3c7033b8202f', 'f1b841e9-a4bf-51d9-b598-0514d6668d0d', 5, 'Interrupting the cycle before it escalates', 'Once you can see a pattern, the next possibility is interruption. Not elimination — patterns do not disappear simply because you have named them. But they can be interrupted at specific points in the cycle, and interruption creates the possibility of a different outcome. Most emotional patterns have a cycle. Something triggers the pattern, the pattern activates, the behavior occurs, the consequence follows, and the pattern reinforces itself. The cycle can be interrupted at any point, but some points are easier than others. The easiest interruption usually happens early — when the activation is just beginning and the emotional intensity is not yet at its peak. This requires learning to recognize your own early warning signs. The first hint of the familiar tension. The slight shift in your body. The early form of the thought or the impulse. These early signals are the most accessible entry points because the pattern has not yet built momentum. What does interruption actually look like? It is usually very small. A pause. A breath. A phrase you say to yourself that names what is happening. A physical movement that creates a brief interruption in the automatic sequence. Small interruptions are not dramatic. They do not require superhuman self-control. They just require a moment — and the intention to use it.', 'This week: practice one interruption. It does not need to be perfect. Just one moment where you choose differently.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('73f080ed-053e-5352-ac20-676b0d0ff659', '8eff9512-def9-51a8-8e89-3c7033b8202f', 1, 'What are your early warning signs that a pattern is activating — the first signals before the behavior has fully taken over?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('68224bd7-147a-54c9-a542-d335d1d0014f', '8eff9512-def9-51a8-8e89-3c7033b8202f', 2, 'Where in the cycle is it most realistic for you to interrupt it right now — what point is most accessible?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('671ba45f-2cfc-56e8-9b0e-a578ac92e7cd', '8eff9512-def9-51a8-8e89-3c7033b8202f', 3, 'What is one small interruption strategy that might work for your specific pattern?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('9409bd4f-7549-5a98-af76-e66ee7af6230', 'f1b841e9-a4bf-51d9-b598-0514d6668d0d', 6, 'Communicating your emotional state clearly', 'Most interpersonal conflict is not actually about the content of what was said. It is about the emotional state that was communicated — often unintentionally — underneath the words. The frustration that bled through the email. The tension that shaped the conversation before either person spoke. The withdrawal that the other person experienced as rejection without knowing what caused it. Communicating your emotional state clearly is one of the highest-leverage skills in relationships and in work. Not every situation calls for it. But the situations where unexpressed or poorly expressed emotional states are causing the most friction — those situations almost always improve when the emotional layer is named. What does it look like to communicate your emotional state clearly? It looks like naming the experience, not the judgment. ''I am finding this harder than I expected'' is clearer than ''you are being unreasonable.'' ''I am feeling overwhelmed right now'' is clearer than ''this is impossible.'' ''I am struggling to stay present in this conversation'' is clearer than withdrawing without explanation. The goal is not to make every interaction emotional. The goal is to reduce the unspoken static that occurs when your internal experience is significantly out of alignment with what is being communicated.', 'This week: in one conversation where you notice a significant gap between your inner experience and what you are expressing, name one true thing about how you feel.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('9c741c11-5b74-55e5-8dcd-7257fbb704ec', '9409bd4f-7549-5a98-af76-e66ee7af6230', 1, 'In which relationships or contexts do you find it most difficult to communicate your emotional state clearly — and why?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('f0577af0-03ac-5401-b2ef-063d1eee343d', '9409bd4f-7549-5a98-af76-e66ee7af6230', 2, 'What tends to happen when your emotional state is not communicated — how does it typically leak out instead?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('aaffed9b-9163-51c4-abf5-acdbcfba3430', '9409bd4f-7549-5a98-af76-e66ee7af6230', 3, 'What would it look like to say something true about what you are experiencing in one situation this week?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('6fa4e55d-208e-559b-8f7a-ade8c8a9f001', 'f1b841e9-a4bf-51d9-b598-0514d6668d0d', 7, 'Building self-awareness as a daily practice', 'Self-awareness is not a fixed trait that you either have or don''t have. It is a practice — something that develops through consistent, deliberate attention to your own inner experience. And like any practice, it builds through repetition rather than intensity. The most effective self-awareness practices are brief and regular. Not a weekly deep-dive that takes two hours — a daily two-minute check-in that becomes habitual. The question is simply: what am I actually feeling right now? Not what I think I should be feeling, not a story about why I feel this way, not a problem to be solved. Just the honest, present-moment answer to what is actually here. This practice, done consistently, changes the relationship between you and your emotional experience. It reduces the gap between when a feeling arrives and when you become aware of it. It builds the language for your inner experience — which makes it possible to name feelings more precisely, which makes them more navigable. And over time, it builds a kind of internal witness — a part of you that can observe your experience without being fully consumed by it. You have been developing this capacity throughout this path. The invitation now is to keep developing it — not because you have a problem to fix, but because the quality of your inner life, and of every relationship in your outer life, depends on it.', 'Closing commitment: Design your daily self-awareness practice. One question. Two minutes. Same time each day. Write it down and start tomorrow. |');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('ea2494e6-2f42-5d16-889c-157fc0b84c20', '6fa4e55d-208e-559b-8f7a-ade8c8a9f001', 1, 'What has shifted in your self-awareness over the course of this path — what do you see more clearly about your own patterns now?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('353d1035-354c-5f05-b955-955ca89d607b', '6fa4e55d-208e-559b-8f7a-ade8c8a9f001', 2, 'What is the simplest daily practice that would help you maintain and deepen the self-awareness you have been building?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('4f3d1946-4fe3-5575-98a0-26aefe808cc9', '6fa4e55d-208e-559b-8f7a-ade8c8a9f001', 3, 'What is the one pattern or insight from this path that you most want to carry forward?');
INSERT INTO public.path (id, name, description, tier, pillar, "subMode", "sessionsCount", classifications, "triggerSignals") VALUES ('5fa6c614-0790-5690-a22f-3befea9ec6eb', 'Living Through Disruption', 'Emotional Well-being  ·  General Emotional  ·  Any classification  ·  Recommended with grief_mode_active \= yes', 'pro', 'emotional', 'general_emotional', 8, 'Any classification', 'enrollment:onboarding; flag:Recommended with grief_mode_active \= yes');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('e81b353d-13eb-566e-b7ce-692491c3720d', '5fa6c614-0790-5690-a22f-3befea9ec6eb', 1, 'Naming what this disruption is and what it has actually cost you', 'Disruption is the word we use when the structure of our lives changes faster than we can adapt. A death, a divorce, a diagnosis, a job loss, a family crisis, a move, a rupture in a relationship that seemed stable — any of these can create the particular disorientation that comes from having the ground shift beneath you. The first thing most people do with disruption is manage it. They stay busy, stay functional, stay in motion — because stopping long enough to actually look at what happened feels dangerous. If I sit still, I might fall apart. If I name what this cost me, it might become more real than I can hold. But the cost of not naming it is that it stays unnamed. The grief, the loss, the fear, the disorientation — all of it sits just below the surface, shaping everything without being acknowledged. You carry the weight of it without ever being able to put it down fully, because you cannot put down what you have never fully picked up. This path begins with naming. Not fixing, not moving on, not silver-lining. Just naming what actually happened, and what it actually cost — in your relationships, your sense of who you are, your plans for the future, your safety, your trust. All of it. Named honestly.', 'This week: write a full account of what happened and what it has cost. Not for anyone else to read — just for you to say out loud to yourself.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('1f397e4a-e807-5c2f-9e5a-5ddb22077a4f', 'e81b353d-13eb-566e-b7ce-692491c3720d', 1, 'What is the disruption you are living through — name it clearly and completely, including the parts that are hardest to say?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('cc6c6770-d13e-5f13-98a7-adb2cdcbca2e', 'e81b353d-13eb-566e-b7ce-692491c3720d', 2, 'What has this disruption actually cost you — not just the obvious losses, but everything that went with it?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('6fa12774-3069-5f89-a768-d0f24ae285e9', 'e81b353d-13eb-566e-b7ce-692491c3720d', 3, 'What have you been avoiding naming about this disruption, and what makes it difficult to name?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('7a493796-e871-5810-8fdc-64bd502ff21a', '5fa6c614-0790-5690-a22f-3befea9ec6eb', 2, 'The identity shift that comes with major life change', 'Major disruptions change us. Not because we decide to change, but because the circumstances that defined us shift, and the person who existed in those circumstances cannot survive unchanged. If your identity was deeply bound up in a role that is now gone — a relationship, a job, a stage of life, a version of yourself — the disruption does not just change your circumstances. It changes who you are. And that identity loss is often one of the most disorienting and least talked-about aspects of major life change. You are in a transition period — not just of circumstances, but of self. The person you were before this disruption had certain certainties, certain roles, certain ways of understanding who they were and what their life was about. Some of those things may still be true. Others are no longer available. What is being asked of you is not to figure out who you will be on the other side. That clarity comes later, slowly, through living. What is being asked right now is to tolerate not knowing — to be in the question of who you are without requiring an immediate answer. This is genuinely difficult. It is also where something important becomes possible.', 'This week: write two lists. Who I was before. What I know is still true. The gap between them is where you are right now.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('36b351fc-60bb-584b-b3ef-a16769c0df36', '7a493796-e871-5810-8fdc-64bd502ff21a', 1, 'What parts of your identity were tied to what has been disrupted — what did you understand yourself to be, that you are no longer sure of?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('5248d5c1-75fe-54df-b7de-c68546c9847d', '7a493796-e871-5810-8fdc-64bd502ff21a', 2, 'What remains — what is still true about who you are even in the middle of this change?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('b4659d28-c1e3-51a5-b001-fd129d3f7ae9', '7a493796-e871-5810-8fdc-64bd502ff21a', 3, 'What would it mean to be in the question of who you are becoming, without needing to have the answer right now?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('748db736-9615-5874-9233-dc5c9156fcad', '5fa6c614-0790-5690-a22f-3befea9ec6eb', 3, 'What your nervous system is doing and why', 'When your life changes dramatically and suddenly, your nervous system responds as if to physical threat — because from the brain''s perspective, loss of predictability and safety is threat. The activation, the hypervigilance, the sleep disruption, the difficulty concentrating, the physical tension — these are not signs that you are failing to cope. They are signs that your nervous system is doing exactly what it does in the face of genuine danger. The particular challenge of life disruption is that there is often no clear resolution of the threat — no moment when the predator runs away and the stress cycle can complete. The disruption continues, or its aftermath continues, and the nervous system stays activated without knowing it is safe to come down. Understanding this does not make it immediately better. But it does change the relationship to the experience. You are not falling apart. You are a nervous system in an activated state that has not yet found its way back to baseline. That requires time, safety, and gentleness — not willpower or discipline. The regulation practices from earlier paths are especially important here. Not because they will fix the disruption, but because they give your body something to do with the activation energy — a way to complete cycles that would otherwise accumulate.', 'This week: identify one regulation practice and use it once daily. The goal is not to feel better immediately — it is to give your system something to work with.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('36bce12a-ce60-50bc-b498-5e3a45b84874', '748db736-9615-5874-9233-dc5c9156fcad', 1, 'What is your nervous system doing right now — what are the specific physical and psychological symptoms of the activation you are carrying?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('f6ef0a23-3375-54f3-9a31-f64ba4e7cfc7', '748db736-9615-5874-9233-dc5c9156fcad', 2, 'What has helped your nervous system settle, even temporarily, during this period?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('9883d74d-ff92-5ae5-bc2c-f33137db6cd5', '748db736-9615-5874-9233-dc5c9156fcad', 3, 'What are you doing that is adding to the activation rather than helping it complete?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('e6b857f3-f8d6-5784-9191-fbd12ca7081b', '5fa6c614-0790-5690-a22f-3befea9ec6eb', 4, 'Grieving the life you thought you would have', 'One of the least visible losses in major life disruption is the loss of the future you thought you were moving toward. The relationship you thought would continue. The career you thought was secure. The version of your life at fifty that you had been unconsciously imagining and are now not going to have. This future is real, even though it never happened. You made decisions based on it. You organized your hopes around it. You built plans and expectations in its direction. The loss of an imagined future is a genuine loss, and it deserves to be grieved — even though there is nothing concrete to point to, nothing that was ever physically present that is now gone. Grieving the life you thought you would have is uncomfortable because it can feel like ingratitude for what you still have, or like you are holding on to something that was never real in the first place. Neither of these things is accurate. The future you imagined was real in the sense that mattered — it shaped your choices and your sense of direction. Its loss is a real loss. Give yourself permission to grieve it, alongside everything else.', 'This week: write a letter to the future you thought you were going to have. Say what you needed to say about it.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('5794c1b3-e693-5e19-b563-b6735ed6198b', 'e6b857f3-f8d6-5784-9191-fbd12ca7081b', 1, 'What future were you imagining that this disruption has taken from you — what was the life you thought you were moving toward?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('8b26070d-c201-5d23-8286-79dbb4c03aaa', 'e6b857f3-f8d6-5784-9191-fbd12ca7081b', 2, 'What decisions did you make based on that future that now feel like they are hanging in a different kind of air?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('004cd954-3d4a-5f44-8fca-5cb063661795', 'e6b857f3-f8d6-5784-9191-fbd12ca7081b', 3, 'What would it mean to give yourself permission to grieve that version of the future, without minimizing it because it was never guaranteed?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('bab10fe7-5f06-5381-be8b-0553dafb465b', '5fa6c614-0790-5690-a22f-3befea9ec6eb', 5, 'Rebuilding structure around a different reality', 'One of the first casualties of major disruption is structure. The routines, rhythms, and predictabilities that organized daily life were often more dependent on the disrupted circumstances than you realized until they were gone. And when structure dissolves, the sense of groundlessness increases — because structure is not just practical, it is a form of psychological safety. Rebuilding structure in the aftermath of disruption is not the same as returning to the old structure. The old structure was built around circumstances that no longer exist. The new structure has to be built around the reality that is actually here. This means starting very small. You are not building your ideal daily life right now. You are building enough structure to function — enough predictability to reduce the sense of free-fall, enough rhythm to give the day some shape. The minimum viable structure is very simple: a consistent time to wake up, one or two consistent anchors in the day, and a consistent way to end it. The temptation is to either try to recreate the old structure (which no longer fits) or to abandon structure entirely because it all feels meaningless right now. Neither of these serves you. A small amount of genuine structure, built for this reality, is the beginning of something.', 'This week: identify one small structural anchor — something consistent and daily. Do it for seven days.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('81a0e2ed-178d-5906-9e03-05ac361dd549', 'bab10fe7-5f06-5381-be8b-0553dafb465b', 1, 'What structure from before the disruption no longer works or no longer fits — what has dissolved?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('4044cf40-045c-5508-8511-86fa2719cae6', 'bab10fe7-5f06-5381-be8b-0553dafb465b', 2, 'What small amount of structure would help you feel more grounded right now — not the ideal routine, just the minimum that would help?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('3878c71f-602a-539b-b4b3-64eeb6766fce', 'bab10fe7-5f06-5381-be8b-0553dafb465b', 3, 'What would you need to accept about your current reality in order to build structure that actually fits it?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('98181d83-f106-5953-bf3e-89b7818126e6', '5fa6c614-0790-5690-a22f-3befea9ec6eb', 6, 'Relationships that shift when your life changes', 'Major life disruptions almost always change relationships. Not always in the ways you expect, and not always negatively — but change happens, and it is often surprising and sometimes painful. Some relationships prove to be more conditional than you knew. They were built around the version of you that existed before the disruption — around shared circumstances, shared roles, shared assumptions about who you were. When those things change, the relationship sometimes does not survive the change, or becomes significantly different. Some relationships deepen. The disruption creates the conditions for a kind of honesty and intimacy that was not accessible before — people who show up in ways that surprise you, connections that become more real because the pretense has been stripped away. And some relationships create new complications. People who want you to be further along than you are, who become uncomfortable with the length of your grief or the depth of your change, who need you to be okay in order to be okay themselves. Navigating the relational landscape of major disruption requires both honesty about what you need and some tolerance for the fact that other people have their own limits and their own responses to your change.', 'This week: have one honest conversation with one person about what you actually need from them right now.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('69e4f45d-5e4a-5711-b649-a96278b111a0', '98181d83-f106-5953-bf3e-89b7818126e6', 1, 'Which relationships have shifted since this disruption — which have surprised you in either direction?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('8a61d9d5-3666-587b-8248-0c985b28c7b1', '98181d83-f106-5953-bf3e-89b7818126e6', 2, 'What do you need from the important people in your life right now that they may not fully understand?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('d27299d8-6950-5222-985a-67da2da97232', '98181d83-f106-5953-bf3e-89b7818126e6', 3, 'Is there a relationship that has become more complicated or more strained since the disruption — what would help it?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('e552babe-abef-5a52-ad4f-d812b6d62eed', '5fa6c614-0790-5690-a22f-3befea9ec6eb', 7, 'Finding footing when the ground is still moving', 'You do not need the ground to be fully stable to begin to find footing. Footing in disruption is not about having certainty — it is about having enough stability to function, to be present, to make one decision at a time without requiring the whole path to be clear. Finding footing looks different for everyone. For some people it is reconnecting with something that predates the disruption — a value, a practice, a part of themselves that was not caught up in what changed. For some it is naming one thing that is still true about who they are and what matters to them. For some it is a small commitment to one day, just one day, of deliberate presence. The footing is always partial and always temporary in the early stages. You will find it and lose it. Find it again. That is how it works. The finding is not a sign that you are through the disruption. It is a sign that you are in it and still moving — which is what getting through actually looks like. You are doing something genuinely hard. You are still here. That is footing enough to continue.', 'This week: name your footing. One true thing. Stand on it.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('efa7e213-8acc-57b7-b1e2-162867805155', 'e552babe-abef-5a52-ad4f-d812b6d62eed', 1, 'What is one thing that still feels true about you — unchanged by the disruption — that you can stand on right now?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('45a8d15a-b6f4-5bad-ba85-38272bcac046', 'e552babe-abef-5a52-ad4f-d812b6d62eed', 2, 'What does finding footing look like in the next 24 hours — not the next year, just today and tomorrow?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('3fbe59b4-1057-5543-9ac7-5ec19877d63b', 'e552babe-abef-5a52-ad4f-d812b6d62eed', 3, 'What small evidence of your own resilience can you point to from this period — something you have done that took something?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('d7fbadf3-4932-5cd3-a08a-158c054ce5d4', '5fa6c614-0790-5690-a22f-3befea9ec6eb', 8, 'What forward looks like — not fixed, not over, but genuinely forward', 'Forward is not the same as recovered. Forward is not the same as over. Forward is simply: moving in a direction rather than staying entirely still, even while carrying everything you are carrying. Most people who have been through major disruption look back at some point and realize that the forward motion began before they felt ready for it. Before the grief was complete, before the ground felt solid, before they understood what they were moving toward. Forward began in spite of not being ready — because life continued, because small choices accumulated, because some part of them kept moving even when another part wanted to stop. What does forward look like for you, right now, at this particular point in this particular disruption? Not the version that requires the disruption to be resolved. The version that is available today, with what you actually have. One thing that is movement rather than stasis. One direction that is toward rather than away. One small, honest step. You do not have to be okay to begin moving forward. You do not have to have it figured out. You do not have to know where forward leads. You just have to take one step in a direction that feels true. And then another.', 'Closing commitment: You made it through this path. Write down what forward looks like this week. One step. Not a plan — a step. |');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('4f2b5a65-0059-55b7-b076-a793b2a070e1', 'd7fbadf3-4932-5cd3-a08a-158c054ce5d4', 1, 'What does forward look like for you right now — not eventually, but in this actual week?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('8d6bee50-9c5e-5688-bff5-6c5a40587da6', 'd7fbadf3-4932-5cd3-a08a-158c054ce5d4', 2, 'What has this period of disruption revealed about you — about your capacity, your values, your real priorities?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('9a321216-1d15-5f4c-be40-e1d525f632f0', 'd7fbadf3-4932-5cd3-a08a-158c054ce5d4', 3, 'What is the one thing you want to carry forward from this path — the one thing you know now that you did not know before?');
INSERT INTO public.path (id, name, description, tier, pillar, "subMode", "sessionsCount", classifications, "triggerSignals") VALUES ('996337fe-0a1b-5d13-9052-87fd77415197', 'Focus and Follow-Through', 'Professional  ·  General Professional  ·  Performance Stagnation · Capacity Erosion', 'pro', 'professional', 'general_professional', 7, 'Performance Stagnation · Capacity Erosion', 'enrollment:onboarding; flag:None — all users matching classification');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('cb29aeb4-c674-57d9-b4f1-92ab9f5a0ee5', '996337fe-0a1b-5d13-9052-87fd77415197', 1, 'Why you''re losing focus — the real reasons', 'Focus is not a character trait that you either have or lack. It is a condition — a state that the brain enters under specific circumstances and fails to enter under others. When you cannot focus, something about the current conditions is preventing the brain from settling into deep work. Understanding what that something is matters, because the solution to distraction depends entirely on what is causing it. There are four common causes of lost focus, and they require very different responses. Overload — too much in the mental buffer, the brain moving rapidly between concerns without being able to settle. Fear — avoidance disguised as distraction, the brain finding anything to attend to other than the thing that carries risk of failure or judgment. Wrong work — the absence of genuine engagement because the task is not actually meaningful to you in a way that motivates deep attention. And depletion — exhaustion that has reduced the brain''s capacity for sustained attention regardless of the quality or importance of the work. Before you can address a focus problem, you need to know which type it actually is. Most strategies for improving focus are designed for the overload type. If your focus problem is actually fear or depletion, those strategies will not work and may make things worse.', 'This week: track your distraction for three days. Every time your attention leaves the work, note what took it and how you were feeling before it wandered.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('b45e9994-2ffe-55e7-9800-8a55a26efe42', 'cb29aeb4-c674-57d9-b4f1-92ab9f5a0ee5', 1, 'When you lose focus, which of the four types tends to best describe what is happening — overload, fear, wrong work, or depletion?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('85322f71-bdcc-56b5-8c77-3a6dd130e3d6', 'cb29aeb4-c674-57d9-b4f1-92ab9f5a0ee5', 2, 'What does distraction look like for you specifically — where does your attention go when it leaves the work?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('ffc2c017-b01e-5283-a63b-88f99bad990a', 'cb29aeb4-c674-57d9-b4f1-92ab9f5a0ee5', 3, 'If you are honest about your current focus problem, what is the real reason underneath the surface explanation?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('4ea17a52-2cf6-5414-a97c-fccd9cc8c2d0', '996337fe-0a1b-5d13-9052-87fd77415197', 2, 'Prioritization that actually works', 'Most prioritization systems fail for one of two reasons. Either they are too complex to maintain — requiring more effort to manage than the value they produce — or they confuse urgency with importance, optimizing for responsiveness rather than for what actually matters. The simplest prioritization that consistently works is this: identify the single most important thing you could do today — the thing whose completion would create the most meaningful forward movement. Do that thing before anything else. Not the most urgent thing. Not the thing that has been on your list the longest. The most important thing. This sounds obvious. It is almost universally not practiced. The emails get answered. The meetings happen. The reactive tasks absorb the day. And the most important thing remains undone — which is exactly why the most important thing is usually the thing that has been on your list the longest. The key discipline is protecting the time for the most important thing from being colonized by the urgent but less important things. This is harder than it sounds and requires a specific, recurring decision: what is the one thing today, and what am I willing to not do in order to do it?', 'This week: identify your most important thing each morning before you open email. Block two hours for it before doing anything else.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('4670976d-5c78-59c5-a5dd-a94b1f9f04fa', '4ea17a52-2cf6-5414-a97c-fccd9cc8c2d0', 1, 'What is the most important thing on your professional list right now — not the most urgent, the most important?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('1643fa82-d2b0-5ace-8f30-1967b6bf8b57', '4ea17a52-2cf6-5414-a97c-fccd9cc8c2d0', 2, 'When and why does that thing consistently get deprioritized in favor of more reactive tasks?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('34a6bdea-9b49-5c7e-9e3a-137c469478e8', '4ea17a52-2cf6-5414-a97c-fccd9cc8c2d0', 3, 'What would you have to decline or delay in order to protect time for the most important thing this week?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('d47c5ab0-25b6-5eee-9fcd-4684d53fd32f', '996337fe-0a1b-5d13-9052-87fd77415197', 3, 'The commitment gap — intention versus execution', 'The commitment gap is the space between what you intend to do and what you actually do. Almost everyone who struggles with execution has it. The gap is not a moral failing. It is a predictable consequence of how human motivation actually works — inconsistently, and highly dependent on the conditions of the moment. Intentions are formed in one mental state — usually a relatively calm, forward-looking state where the future is vivid and the cost of the action seems small. But execution happens in different conditions — often when you are tired, distracted, pulled by other demands, or in a state where the discomfort of starting feels larger than it did when you made the commitment. The bridge across the gap is not willpower. Willpower is unreliable and depletes. The bridge is environmental design — making the intended behavior easier to start and the competing behaviors harder to access — combined with specificity about when, where, and how the behavior will occur. The most powerful change you can make to a commitment is to attach it to a specific time and a specific context: ''I will do X at Y o''clock in Z location.'' Vague intentions fail. Specific implementation intentions succeed at a dramatically higher rate.', 'This week: take your most important commitment and make it specific. Time. Place. Action. Write it where you will see it.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('33d3b402-7eea-59a2-8549-d1a9cfbe2a9e', 'd47c5ab0-25b6-5eee-9fcd-4684d53fd32f', 1, 'What is the most consistent gap between your professional intentions and your actual behavior — where does execution reliably break down?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('1dd2b2b6-64ec-5b8a-a6bc-bbbfdf2345f2', 'd47c5ab0-25b6-5eee-9fcd-4684d53fd32f', 2, 'What is happening in the moments when you fail to follow through — what are the conditions that make not-doing easier than doing?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('e67fbb3f-29bc-5309-9249-b6f4b3933d4a', 'd47c5ab0-25b6-5eee-9fcd-4684d53fd32f', 3, 'What one commitment could you make more specific this week — with a time, a place, and a specific action?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('9f0dc71d-f477-5fef-9046-2b6e8206bb71', '996337fe-0a1b-5d13-9052-87fd77415197', 4, 'Building follow-through as a habit', 'Follow-through is not a personality trait. It is a skill — specifically, the skill of reducing the friction between intention and action until the action requires less deliberate decision-making. Like any skill, it builds through practice. And like any habit, it becomes more reliable as the conditions that support it become consistent. The habits that make follow-through most reliable are structural: consistent time blocks for specific types of work, consistent start rituals that signal to the brain that it is time to focus, consistent review practices that close loops and set direction for what comes next. These structural habits take the decision-making load off the moment of action — you do not have to decide whether to start, because the structure decides for you. The other ingredient is momentum. Small, consistent completions build the expectation of completion. When you have a track record of doing what you said you would do — even in small things — the friction of doing it again is lower. The brain has evidence that follow-through is possible and that the discomfort of starting is temporary. That evidence is worth more than any motivational strategy.', 'This week: complete one commitment fully, every day, for seven consecutive days. Choose something small enough that completion is realistic.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('b893cf74-2bd1-5842-9c1c-c9e34b6fd226', '9f0dc71d-f477-5fef-9046-2b6e8206bb71', 1, 'What is your current follow-through pattern — what tends to happen to your commitments over the course of a week?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('7e146d42-9457-551b-94bd-e5fb07a9c478', '9f0dc71d-f477-5fef-9046-2b6e8206bb71', 2, 'What structural changes would make follow-through more automatic and less dependent on in-the-moment motivation?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('f5a73fa6-366b-5cc2-a666-af17c279f535', '9f0dc71d-f477-5fef-9046-2b6e8206bb71', 3, 'What is one small commitment you could build consistent follow-through around this week — specific enough to measure?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('3f619a4b-ff34-5fd5-a4fc-8fb528ed52f7', '996337fe-0a1b-5d13-9052-87fd77415197', 5, 'Protecting your most productive hours', 'Most people have a window of two to four hours during the day when their cognitive capacity is at its peak — when the brain is freshest, most creative, and best able to do the kind of deep, complex work that actually matters. Almost universally, people spend those hours on the least important things: email, meetings, reactive tasks, administrative friction. Protecting your most productive hours means identifying when they are and treating them as non-negotiable for your most important work. This requires saying no to things that feel urgent but are not important. It requires disappointing people occasionally. It requires a different relationship with availability. The most productive people in almost every field have this in common: they treat a specific window of time as sacred, fill it with their most important work, and allow everything else to happen in the remaining hours. The specific window varies — some people are most productive in the early morning, others late afternoon — but the principle is consistent. You cannot protect time you have not first identified and claimed. The first question is: when are you actually at your best? The second is: what would it take to protect that window consistently?', 'This week: identify your peak hours and protect them for three days. No email, no meetings, no reactive tasks during those hours. Notice the output.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('b1d0024f-1a88-5dfc-a3fc-1e28c882bc6e', '3f619a4b-ff34-5fd5-a4fc-8fb528ed52f7', 1, 'When during the day is your cognitive capacity genuinely at its peak — when are you actually at your best?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('bbdea60f-e967-51f4-84b9-f251aa89a96d', '3f619a4b-ff34-5fd5-a4fc-8fb528ed52f7', 2, 'What consistently invades those hours — what demands or habits colonize your most productive time?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('dd1e78b6-80c6-5415-945d-75f929dd09d7', '3f619a4b-ff34-5fd5-a4fc-8fb528ed52f7', 3, 'What is one specific change you could make this week to protect your best hours for your most important work?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('28a14803-6625-52a1-99c6-dc836e3aeccc', '996337fe-0a1b-5d13-9052-87fd77415197', 6, 'Managing interruptions and context switching', 'Every interruption has a cost that extends well beyond the interruption itself. Research on attention consistently shows that returning to deep work after an interruption takes significantly longer than the interruption — often fifteen to twenty minutes. This means that a day with many interruptions, even brief ones, may produce almost no deep work despite hours of apparent effort. Context switching — moving rapidly between different types of tasks, each requiring a different mental setup — is similarly costly. Each switch requires the brain to unload the previous context and load the new one. In high-frequency switching, the brain spends so much time on loading and unloading that very little actual work occurs during the switching itself. The solution is not to eliminate interruptions entirely — that is neither realistic nor always desirable. The solution is to batch them. To designate specific times for reactive work — email, messages, meetings — rather than allowing them to interrupt throughout the day. To create clearly bounded windows for deep work that are defensible from intrusion. Batching requires communicating expectations to others — letting people know when you are and are not available, and building the trust that you will respond during the designated windows rather than immediately.', 'This week: batch email and messages into two designated windows per day. Protect the rest for focused work. Notice the difference.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('4d1cb0da-76f5-55fe-b58d-fee9a3c7f596', '28a14803-6625-52a1-99c6-dc836e3aeccc', 1, 'How many interruptions do you typically experience during your work hours — and what do they tend to be?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('56482ea1-cc5f-52fa-9617-3cda771371cf', '28a14803-6625-52a1-99c6-dc836e3aeccc', 2, 'What is the actual cost of those interruptions to your most important work — what does not get done because of them?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('897b16d6-dacb-574c-abbc-483121618d4c', '28a14803-6625-52a1-99c6-dc836e3aeccc', 3, 'What would a realistic batching strategy look like for your specific role and context?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('aedcbb38-0cda-52d6-9ce4-6e1f640749d9', '996337fe-0a1b-5d13-9052-87fd77415197', 7, 'Weekly review as a performance tool', 'The weekly review is one of the highest-leverage practices available to anyone who wants to improve their professional performance, and it is one of the most commonly abandoned. It is abandoned because it feels like overhead — time spent reviewing rather than doing. It is high-leverage because the cost of not reviewing is an accumulation of unclosed loops, missed priorities, and repeated patterns that never get examined. A useful weekly review takes between thirty and sixty minutes and addresses three questions: What actually happened this week — what did I complete, what did not happen, and what created the gap? What are the most important things for the coming week — and do I have the time blocked for them? What are the patterns — what am I consistently not doing, and what does that tell me? The pattern question is the most valuable and the most commonly skipped. Your week is a data set. Across multiple weeks, patterns emerge — things that consistently fall off, decisions that consistently get avoided, times that consistently get colonized by the wrong work. The weekly review is how you see those patterns before they have run for months or years. This path closes with the invitation to begin a weekly review practice. Not perfect — sustainable. Thirty minutes. Same time each week. The three questions. And the willingness to be honest about what the data says.', 'Closing commitment: Schedule your weekly review for the next four weeks. Same time. Block it now. |');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('7191c8b4-d651-5067-b02e-634aff458f0a', 'aedcbb38-0cda-52d6-9ce4-6e1f640749d9', 1, 'When you think about the past few weeks, what are the patterns — what consistently happens that you do not intend, and what consistently does not happen that you do intend?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('7828a07f-c7cc-541a-8429-923e821094e4', 'aedcbb38-0cda-52d6-9ce4-6e1f640749d9', 2, 'What is the most important thing you learned about your own performance during this path?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('46de9c8c-ef57-5db4-bd65-77cd3cc77b4d', 'aedcbb38-0cda-52d6-9ce4-6e1f640749d9', 3, 'What would a sustainable weekly review practice look like for you — when, where, and what specific questions?');
INSERT INTO public.path (id, name, description, tier, pillar, "subMode", "sessionsCount", classifications, "triggerSignals") VALUES ('60b456bb-3e86-5dd0-9a3a-6dbac3fc6fe7', 'Sustainable High Performance', 'Professional  ·  General Professional  ·  High Output/Hidden Instability · Optimization Ready', 'pro', 'professional', 'general_professional', 8, 'High Output/Hidden Instability · Optimization Ready', 'enrollment:onboarding; flag:None — all users matching classification');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('5f2965ea-438c-5ac9-96e6-b28b8911daff', '60b456bb-3e86-5dd0-9a3a-6dbac3fc6fe7', 1, 'Defining sustainable performance for your actual life', 'High performance is not a fixed state. It is a dynamic relationship between demand and capacity — and sustainability is what allows that relationship to continue over time rather than ending in a crash. Most high performers have a definition of performance that was formed in a specific context — often early in their career, or during a particular stretch of effort that produced results. That definition tends to be about output: hours worked, problems solved, goals achieved, standards met. It rarely includes recovery, or restoration, or the conditions that make the output possible. Sustainable performance requires a different definition — one that includes not just what you produce but what you need to keep producing it. What does your best work actually require? Not your average work, and not your survival work — your best work. The kind that you are most proud of and that produces the most meaningful results. This session is an invitation to define sustainability on your own terms, for your actual life — not as a concession to your limitations, but as the most intelligent approach to performing at a high level over the long arc of a career.', 'This week: write your definition of sustainable performance for your specific life. Not someone else''s ideal — yours.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('0cc42c62-dacf-537c-a56e-69aa88ddcf45', '5f2965ea-438c-5ac9-96e6-b28b8911daff', 1, 'What does your definition of high performance look like right now — what are you trying to sustain, and at what cost?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('4de587cf-fbc6-5590-b940-641de1aaab73', '5f2965ea-438c-5ac9-96e6-b28b8911daff', 2, 'What would need to be true for your current level of output to be genuinely sustainable over the next five years?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('9b6ed741-358b-5344-a7ce-5e90af511ef9', '5f2965ea-438c-5ac9-96e6-b28b8911daff', 3, 'If you designed your professional life for the long game rather than the current sprint, what would change?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('ed014f55-c5f6-5258-9b99-aabcf592c56f', '60b456bb-3e86-5dd0-9a3a-6dbac3fc6fe7', 2, 'Identifying where you''re subsidizing output with your health', 'Performance has a cost structure. Every hour of output requires inputs — cognitive capacity, emotional regulation, physical energy, attention. When those inputs are consistently less than the outputs they are supporting, the difference is borrowed. From sleep. From recovery. From relationships. From health. From future capacity. This is subsidized performance. It looks like high output. It produces real results. And it is drawing down a reserve that will eventually reach zero. The signs of subsidized performance are not always dramatic. They tend to be subtle and accumulating: the quality of your thinking declining in the latter part of the day. The patience for people wearing thinner. The things that used to restore you failing to restore. The baseline getting lower without a noticeable acute cause. The sleep that does not fully recover the exhaustion. The question is not whether you are subsidizing. Almost every high performer is, to some degree. The question is how much, and whether you are aware of it, and whether the current rate of subsidy is sustainable or is accelerating toward a cliff.', 'This week: honestly assess your subsidy. Write down what you are borrowing from. Name the rate.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('b5e03d03-0026-515f-8cde-27624f498fb9', 'ed014f55-c5f6-5258-9b99-aabcf592c56f', 1, 'Where specifically are you subsidizing your current output — what are you borrowing from to maintain the pace?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('f963778b-2010-5a7d-88a8-ccc7c7faabe2', 'ed014f55-c5f6-5258-9b99-aabcf592c56f', 2, 'What are the signs that the subsidy is occurring — the specific signals in your body, your quality of work, your relationships?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('b2cbb159-c879-592f-a07e-b13d9828a165', 'ed014f55-c5f6-5258-9b99-aabcf592c56f', 3, 'If you continue at the current rate without change, what do you think happens — in six months, in two years?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('339c5fee-046e-52ca-bded-e4c92d09d15a', '60b456bb-3e86-5dd0-9a3a-6dbac3fc6fe7', 3, 'Recovery as a professional strategy', 'Recovery is not the opposite of performance. It is a component of performance — specifically, the component that allows performance to continue. Every elite athlete understands this. The training produces the stress. The recovery produces the adaptation. Without recovery, training just depletes. The same principle applies to cognitive and emotional performance. The deep work depletes. The recovery produces the adaptation. The rest that follows a period of intense focus is not lost time — it is the time during which the brain consolidates, integrates, and rebuilds the capacity for the next period of intense focus. The reason most high performers have a difficult relationship with recovery is that recovery does not feel productive. It does not produce visible output. In a culture and a professional environment that rewards output, recovery is invisible — and what is invisible is often sacrificed first. Recovery that actually works — that genuinely restores cognitive and emotional capacity — requires real disengagement. Not passive consumption of stimulating content. Not social obligation. Not half-work. The kind of rest that allows the nervous system to fully downregulate and the brain to enter its restorative states. This is harder to achieve in a high-stimulation environment than most people realize, and it requires intentional design.', 'This week: protect one genuine recovery block. Real rest. Something that fully disengages. Treat it as non-negotiable.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('9a1ba005-999e-54ac-b0e4-6074fd92384d', '339c5fee-046e-52ca-bded-e4c92d09d15a', 1, 'What does your current recovery actually look like — and does it genuinely restore capacity, or does it just pause the depletion?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('15970d76-6d65-52e1-bc12-2ff64440f633', '339c5fee-046e-52ca-bded-e4c92d09d15a', 2, 'What activities most effectively restore your specific kind of capacity — what actually helps your mind and body reset?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('7c111839-1c4a-5bd5-bd29-0267291f691a', '339c5fee-046e-52ca-bded-e4c92d09d15a', 3, 'What would you have to change about your current schedule to make genuine recovery a structural part of your week?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('a5a9e187-a0aa-5ecf-9def-c21c88a4965b', '60b456bb-3e86-5dd0-9a3a-6dbac3fc6fe7', 4, 'Saying no as a performance decision', 'Every yes has a cost. The yes to one project is a no to another — or to recovery, or to depth in the work you have already committed to, or to the people who depend on you. Most high performers are aware of this in the abstract. Very few have internalized it enough to let it consistently govern their decisions. The inability to say no is usually rooted in one of several beliefs: that saying no reflects a lack of capacity or ambition; that the relationship or opportunity will be lost if you decline; that you should be able to do more than you are doing; or that other people''s needs and requests have a higher claim on your time than your own priorities. Each of these beliefs is worth examining. The high performer who says yes to everything produces a lot of work. Some of it is excellent. Most of it is adequate, because the time and cognitive depth required for excellence cannot be divided into thirty different directions without dilution. The no that protects your capacity for excellence is not a failure of ambition. It is the expression of a standard for your own work that refuses to be diluted. The performers whose work you most admire almost certainly say no to more things than you do.', 'This week: say no to one thing. Practice the language. Notice the discomfort and notice that the relationship and the world survive.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('7ae17e29-8a85-57ca-aeed-74999846d9a1', 'a5a9e187-a0aa-5ecf-9def-c21c88a4965b', 1, 'What are you currently saying yes to that is costing your ability to do your most important work with full capacity?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('7ab21251-e92d-5f92-bc78-186956cf9f17', 'a5a9e187-a0aa-5ecf-9def-c21c88a4965b', 2, 'What stops you from saying no to more things — what are the specific beliefs or fears that drive over-commitment?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('5f832753-2a5e-525a-a9bf-fbdbb449decc', 'a5a9e187-a0aa-5ecf-9def-c21c88a4965b', 3, 'What is one thing you could decline this week that would create real space for something that matters more?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('e28b946e-9cbc-537a-aa51-d1b85691c8d6', '60b456bb-3e86-5dd0-9a3a-6dbac3fc6fe7', 5, 'The long game — what you want your career to look like in five years', 'High performance in the short term is not the same as high performance over a career. The sprint strategy that produces extraordinary results in a two-year push often produces burnout, health consequences, and a diminished capacity for the next decade. The long game requires a different orientation — one that treats current capacity as an asset to be maintained rather than a resource to be consumed. It requires asking, regularly, whether the current pace and the current choices are building toward something or drawing down from something. Five years is a useful timeframe for this kind of thinking. Long enough that the effects of current choices will have compounded. Short enough that it is not abstract. In five years, where do you want to be — professionally, personally, physically? Not just in terms of titles or achievements, but in terms of how you feel, how you are functioning, what your days look like, what your relationships are like. And then the backward question: given that destination, are the choices you are making right now pointing toward it or away from it?', 'This week: write your honest five-year picture. Then write whether the current trajectory gets you there.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('f9db3054-44ac-57fa-a0c7-23be78d27d1a', 'e28b946e-9cbc-537a-aa51-d1b85691c8d6', 1, 'Where do you genuinely want to be in five years — not the version you would say publicly, but what you actually want?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('f0a12dcd-c3b4-50c8-8883-55035389cc19', 'e28b946e-9cbc-537a-aa51-d1b85691c8d6', 2, 'Are the current choices pointing toward that destination or creating conditions that will make it less accessible?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('b65436c5-3b42-58a1-a2b2-91c964d5d017', 'e28b946e-9cbc-537a-aa51-d1b85691c8d6', 3, 'What one change to your current approach would most improve the alignment between your choices and your five-year destination?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('77b3bf01-5140-53c0-a867-e3e50d518624', '60b456bb-3e86-5dd0-9a3a-6dbac3fc6fe7', 6, 'Pacing without losing edge', 'The fear underneath most resistance to sustainable performance is this: if I slow down, I will lose my edge. The pace, the urgency, the constant forward pressure — these feel not just like habits but like the source of the performance itself. If I remove the pressure, will the results disappear too? This fear is understandable but usually not accurate. Edge does not come from pace. It comes from clarity, depth, and the quality of attention you can bring to your work. These are all compromised by depletion, not enhanced by it. The high performers who sustain at the highest levels over decades are almost always distinguished not by working more hours than their peers but by the quality of presence they bring to the hours they work. They protect their capacity. They recover. They say no. And as a result, when they are working, they are genuinely, fully there — not depleted and persisting, but present and focused. Pacing is not slowing down below your optimal level. It is finding your optimal level and sustaining it rather than oscillating between unsustainable peaks and depleted troughs. The edge is sharper at sustainable pace than at exhausted peak.', 'This week: experiment with protected recovery before one important piece of work. Note whether the quality is different.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('ce10bca0-3a3f-5f62-a7f3-f0169cf4493f', '77b3bf01-5140-53c0-a867-e3e50d518624', 1, 'What does losing your edge look like for you — what specifically do you fear would change if you slowed down?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('cf872bdb-c568-5c7b-887d-195469172e17', '77b3bf01-5140-53c0-a867-e3e50d518624', 2, 'Is there evidence in your experience that the fear is accurate — has pacing yourself ever actually reduced the quality of your output?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('53182914-86c2-5819-b679-daae630afc57', '77b3bf01-5140-53c0-a867-e3e50d518624', 3, 'What would your work look like if you brought it the same quality of presence but from a more restored state?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('d6e59ffa-977d-5e0d-8127-7f90e7315de9', '60b456bb-3e86-5dd0-9a3a-6dbac3fc6fe7', 7, 'Building the infrastructure for sustained excellence', 'Sustained excellence is not an act of will. It is the output of a system — a set of structures, practices, and commitments that make the quality of the work possible, regardless of how you feel on any given day. The infrastructure of sustained excellence includes: protected time for your most important work, built as a recurring structure rather than a series of individual decisions; recovery practices that are scheduled and defended like any other commitment; a small set of non-negotiables that protect your cognitive and emotional capacity; and a clear, honest assessment of your current load versus your current capacity. Most high performers manage their performance through willpower and intensity. The problem with this approach is that willpower depletes, intensity cannot be sustained, and the whole system is only one hard season away from collapse. Infrastructure is different. Infrastructure holds when you are tired. It runs when motivation is low. It produces results even in the difficult weeks because it has been designed to function without requiring optimal conditions. The work of this session is to identify what your infrastructure needs and what would need to change to build it.', 'This week: implement one structural change. Not a resolution — a structural change. Something that changes the conditions, not just the intentions.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('15c5640f-eee6-5f56-9ffc-45c3dd8369a4', 'd6e59ffa-977d-5e0d-8127-7f90e7315de9', 1, 'What structures currently support your best work — what is already working in your professional infrastructure?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('8972d6ee-8528-5d58-ae6d-127838d28892', 'd6e59ffa-977d-5e0d-8127-7f90e7315de9', 2, 'What is missing from your infrastructure that regularly creates friction or inconsistency in your performance?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('c04caacf-26fc-5029-bc88-79fb93f40a3e', 'd6e59ffa-977d-5e0d-8127-7f90e7315de9', 3, 'What is the one structural change that would create the most meaningful improvement in the sustainability of your performance?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('c6ae1ae2-0f35-56bb-9506-f3d220bc625d', '60b456bb-3e86-5dd0-9a3a-6dbac3fc6fe7', 8, 'Your personal performance operating system', 'By now you have enough information to design something that most high performers never build: a conscious, intentional operating system for your professional life — a set of principles, practices, and structures that reflect your actual capacity, your actual values, and your actual definition of what excellent performance looks like. Most people operate from an inherited system — absorbed from their industry, their culture, their early career environment — without ever stepping back to examine whether it is the right system for them. The inherited system is usually built around the assumption that more is better, that pace equals success, that saying no is failure, and that recovery is weakness. Your operating system might include different assumptions. It almost certainly includes different practices, different time structures, different criteria for what counts as success. It is built from the evidence of what actually works for you — not what works in general, but specifically. This is the lasting outcome of this path: not a set of techniques applied to an unchanged approach, but a genuinely different understanding of how to perform at a high level in a way that compounds rather than depletes.', 'Closing commitment: Write your personal performance operating system. Three to five principles. The practices that support them. Review it monthly. |');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('18e4e9cd-91a8-52f6-b990-8b19b2859dc6', 'c6ae1ae2-0f35-56bb-9506-f3d220bc625d', 1, 'What are the three to five principles that should govern your professional operating system — the things that matter most to you about how you work?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('1ed14efc-db5c-5789-aad7-af0d84eb8f8c', 'c6ae1ae2-0f35-56bb-9506-f3d220bc625d', 2, 'What does your sustainable high performance practice look like — what are you committed to keeping from this path?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('fa86d2af-ec13-525e-8ab8-68990ca7b066', 'c6ae1ae2-0f35-56bb-9506-f3d220bc625d', 3, 'What is the single most important shift this path has produced in how you think about your own performance?');
INSERT INTO public.path (id, name, description, tier, pillar, "subMode", "sessionsCount", classifications, "triggerSignals") VALUES ('3cdedde4-bfe4-5f0a-af73-af5d5b06fb97', 'Breaking Out of the Comfortable Plateau', 'Professional  ·  General Professional  ·  Comfortable Plateau', 'pro', 'professional', 'general_professional', 7, 'Comfortable Plateau', 'enrollment:onboarding; flag:None — all users matching classification');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('62b1f6c5-f000-5805-af48-7d9c7121e6b0', '3cdedde4-bfe4-5f0a-af73-af5d5b06fb97', 1, 'Naming what okay actually feels like', 'There is a particular quality to the comfortable plateau that makes it hard to name. It does not feel bad enough to demand action. Life is objectively fine — maybe even good by most measures. There is nothing obviously wrong. And yet there is a persistent, quiet sense that something is missing. A flatness. An absence of the aliveness that used to be more present. The plateau is named correctly: it is comfortable. The discomfort of it is not intense enough to create urgency. And this is exactly what makes it sticky — there is nothing painful enough to override the comfort of staying, and nothing sufficiently clear pulling you forward. But you are here. Which means some part of you already knows that okay is not enough. Some part of you has been sitting with something — a question, a vague dissatisfaction, a sense of possibility that is not being realized — and that part has finally prevailed enough to bring you to this path. The first honest question is this: what does okay actually feel like for you, right now? Not the version you tell people, and not the version you tell yourself when you are being defensive about the life you have built. The honest version. The private version. The one that knows the difference between contentment and settling.', 'This week: write your honest answer to ''what does okay feel like?'' Do not filter it for reasonableness.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('7c091064-a5f6-5276-b754-2ee669bc083e', '62b1f6c5-f000-5805-af48-7d9c7121e6b0', 1, 'When you sit with your life honestly, what does okay actually feel like — what is the texture of the comfortable plateau you are in?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('1cd946a8-9a68-5799-85c7-1b5f366bab44', '62b1f6c5-f000-5805-af48-7d9c7121e6b0', 2, 'What do you notice yourself not reaching for anymore — what have you stopped trying for, and when did that stop?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('918dc1a4-187f-5ee6-b3f5-04352b1e9b29', '62b1f6c5-f000-5805-af48-7d9c7121e6b0', 3, 'If you could be guaranteed that no one would judge you for the answer, what would you say you actually want that you are not currently moving toward?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('1c8a6237-0fa6-5add-8427-b41ea0adab3a', '3cdedde4-bfe4-5f0a-af73-af5d5b06fb97', 2, 'The drift from ambition to acceptance — how it happens slowly', 'No one decides to settle. The drift into the comfortable plateau happens gradually, through a long series of small decisions that individually seem entirely reasonable. The project that would have required a stretch was passed on because the timing was not right. The conversation about what you actually wanted from this season of your career was postponed because things were going well enough. The vision that used to pull you forward was revised downward, then revised downward again, until it was so modest it no longer generated any pull at all. Each of these decisions was made for good reasons. And the accumulation of good-reason decisions can produce a life that is significantly smaller than the one that was possible. The drift is particularly sneaky because it does not feel like giving up in the moment. It feels like maturity, like practicality, like wisdom about what is realistic. It is only in retrospect — or when you pause long enough to look honestly at the whole arc — that you can see how far the drift has taken you from where you once imagined being. This is not a tragedy. The drift happened. It can also be reversed. But reversing it requires first being honest about the fact that it occurred.', 'This week: trace the drift. When did the ambition start to adjust? Write the honest chronology.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('b99b8c3d-05e9-52c3-b889-dd08507812fe', '1c8a6237-0fa6-5add-8427-b41ea0adab3a', 1, 'Can you trace the drift — when did you start adjusting your ambitions downward, and what was the specific moment or period that started it?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('2e17ce16-186b-557b-a000-e8f6f608a724', '1c8a6237-0fa6-5add-8427-b41ea0adab3a', 2, 'What do you tell yourself about the plateau that makes it feel like a reasonable or even wise place to be?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('88ff938d-3069-519e-975f-8fc3f2476272', '1c8a6237-0fa6-5add-8427-b41ea0adab3a', 3, 'What would you have to admit about your life to acknowledge that you have been settling rather than choosing?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('3589ac72-1789-56b5-a02d-211881309d61', '3cdedde4-bfe4-5f0a-af73-af5d5b06fb97', 3, 'What you have stopped reaching for and why', 'There are things you used to reach for — in your work, your relationships, your sense of self — that you no longer reach for. Some of these things you consciously let go of, and the letting go was right. Others you stopped reaching for not because they stopped mattering but because the reaching became uncomfortable, or the outcome uncertain, or the risk of failure too vivid. The comfortable plateau is often organized around the avoidance of a specific kind of discomfort — the discomfort of wanting something you are not sure you can have. It is safer to stop wanting it than to keep wanting it and risk not getting it. The goal is revised. The ambition is lowered. The reach is withdrawn. And the discomfort of unmet longing is exchanged for the numbness of no longer longing. This exchange is understandable. It is also, in the long run, much more costly than the discomfort it was designed to avoid. The numbness accumulates. The life gets smaller. The part of you that used to reach begins to atrophy. What did you stop reaching for? And is the reason you stopped still valid — or is it a protection against a discomfort that you could now afford to face?', 'This week: name the thing you stopped reaching for. Write why you stopped. Then write whether that reason is still true.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('9ecd25e3-b1b8-54e2-8cc0-d862827cce05', '3589ac72-1789-56b5-a02d-211881309d61', 1, 'What specifically have you stopped reaching for — what did you used to want that you no longer let yourself want?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('ef98305d-3f54-521c-89fa-7f33e7631a63', '3589ac72-1789-56b5-a02d-211881309d61', 2, 'Was the stopping a genuine choice or a protection — what was the specific risk or discomfort you were avoiding?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('a632c982-14b8-5c9b-b275-ce72e555bad2', '3589ac72-1789-56b5-a02d-211881309d61', 3, 'Is that risk or discomfort still as large as it was when you stopped? Has something changed that would make reaching again more survivable?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('64ad6dda-725f-5362-81b2-2cdd9d9a57f9', '3cdedde4-bfe4-5f0a-af73-af5d5b06fb97', 4, 'The quiet life audit — what would you actually change', 'If you could design your professional life right now with full freedom — without the constraint of what others expect, what seems reasonable given where you are, what would require too much disruption — what would you change? This question is worth sitting with honestly, because the gap between your honest answer and your current reality is the information you need. Not that you should immediately act on every part of the gap. But knowing the gap clearly is the beginning of being able to close it deliberately rather than drifting further away from it. The quiet life audit is honest accounting. It does not require you to blow up your current life. It requires you to see it clearly. The parts of it that are genuinely chosen and genuinely good. The parts that are there by drift rather than by decision. The parts that you have been tolerating rather than addressing because addressing them would require something uncomfortable. Most people who do this audit honestly are surprised both by how much is genuinely good and by how much is genuinely not chosen. The audit is not designed to produce dissatisfaction — it is designed to produce clarity. You cannot move toward what you want if you have not first been honest about what that is.', 'This week: do the quiet life audit. Write it privately. Three things you would change. Three things that are genuinely good. The gap between where you are and where you would choose to be.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('c43918d6-dd00-551d-8760-86d7cdf40b1d', '64ad6dda-725f-5362-81b2-2cdd9d9a57f9', 1, 'If you could change three things about your professional life right now, what would they be — honestly?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('107c446f-3e08-50da-8e28-154bdd105614', '64ad6dda-725f-5362-81b2-2cdd9d9a57f9', 2, 'Of those three things, which is most clearly a drift rather than a decision — something you never really chose but just ended up in?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('3f93cc82-7fc4-5ca2-a7de-722dd551241a', '64ad6dda-725f-5362-81b2-2cdd9d9a57f9', 3, 'What would taking the first step toward changing it look like, and what makes that step feel difficult or impossible?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('88268f65-a085-50ea-b2e8-9b0845146526', '3cdedde4-bfe4-5f0a-af73-af5d5b06fb97', 5, 'One area where you know you''re playing smaller than you could', 'You already know. There is always one area — sometimes more, but always at least one — where some honest part of you knows that you are not bringing your full capacity to bear. Where you are holding something back. Where you are playing inside a comfort zone that you could expand if you were willing to accept the discomfort of expanding it. This is not about being harder on yourself. You have probably been hard enough on yourself already. This is about being honest — specifically, without drama or judgment — about where the limitation is self-imposed rather than genuinely circumstantial. The one area might be in your professional output — the level of ambition you allow yourself in your work. It might be in how you show up for others — the depth of presence or honesty you bring to the important relationships. It might be in the pursuit of something you have wanted for a long time but have not allowed yourself to seriously attempt. Name it. Just name it. You do not have to immediately do something about it. But naming it clearly and honestly is the first step toward actually doing something.', 'This week: write the one area. Be specific. Name the hold-back. That is the thing this path is pointing toward.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('e5f8ee95-9b22-5e27-a316-a7da73281a73', '88268f65-a085-50ea-b2e8-9b0845146526', 1, 'Where specifically are you playing smaller than you know you could — what is the one area where you are holding back?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('70b0eb9a-5d51-53eb-bc5b-f4b8a2cdcf58', '88268f65-a085-50ea-b2e8-9b0845146526', 2, 'What specifically is the hold-back — fear of failure, judgment from others, the cost of trying, something else?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('bf9f8c86-51ad-51ca-91b6-2fd00ff8d41e', '88268f65-a085-50ea-b2e8-9b0845146526', 3, 'What would you do differently in this area if you were operating from your full capacity rather than from protection?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('e5eab05a-5e9c-5f02-a196-0de89480b7dd', '3cdedde4-bfe4-5f0a-af73-af5d5b06fb97', 6, 'Reconnecting with what you actually want next', 'Underneath the comfortable plateau, there is usually something you want. It may be buried under years of adjustment and revision and protection, but it is there. The question is whether you are willing to find it and name it — because naming what you want makes the gap between where you are and where you want to be real, and that gap can be uncomfortable to hold. But the alternative — staying in the comfortable plateau and letting the numbness continue to accumulate — has its own cost. The cost is the life you do not live. The version of yourself that you do not become. The work you do not do. The risks you do not take. These are real losses, even though they are invisible ones. What do you actually want next? Not what you think you should want, and not what seems realistic, and not the version you would say to someone you were trying to impress. The honest version. The private version. The version that surfaces when you are quiet and no one is listening. You do not have to have a plan. You do not have to have it figured out. You just have to be willing to know what you want.', 'This week: write what you actually want next. The honest version. Read it back to yourself. Notice what it feels like to name it.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('507e82c1-0ace-58ad-b26a-534aadb9eb02', 'e5eab05a-5e9c-5f02-a196-0de89480b7dd', 1, 'What do you actually want next — honestly, privately, without filtering for reasonableness?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('342bd383-39a6-5d86-b4cd-b1435a150a57', 'e5eab05a-5e9c-5f02-a196-0de89480b7dd', 2, 'What is the gap between that honest want and your current trajectory?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('1a7d4bca-8fdf-50d5-9b5a-dc230c6b7f63', 'e5eab05a-5e9c-5f02-a196-0de89480b7dd', 3, 'What is the smallest possible first step toward the honest want — something real, not aspirational?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('3588f039-4d3a-5ef0-a2e1-ebaa7387f7ce', '3cdedde4-bfe4-5f0a-af73-af5d5b06fb97', 7, 'A first step that is real, not just motivational', 'The comfortable plateau is littered with first steps that were announced but not taken. This path is not trying to produce another motivational moment that fades by next week. It is trying to produce one actual step — something concrete, irreversible enough to create a new fact, small enough to be genuinely doable. A real first step is specific. It has a date. It has a clear action. It results in something different than the current situation — not a plan, not a commitment to make a plan, but an action. It may be small. It should be small. Small first steps that actually happen beat large aspirational ones that remain aspirational. The test of whether a first step is real is whether it would feel like something if you did not do it — whether you would feel the absence of taking it. If the step is too abstract or too distant, it will not create that feeling. If it is specific and near and yours, it will. This path began with naming the comfortable plateau honestly. It closes with a real first step in a direction that is more alive than okay. Not a transformation — a step. Real, specific, yours.', 'Closing commitment: Name your first step. Name the date. Tell one person. Take it. | | Batch 2 Complete · Paths 9–13 · 35 Sessions Total across Paths 1–13: 101 sessions complete Remaining: Batch 3 · Paths 14–18 · Foundations of Balanced Life · Building Daily Structure · 30-Day Foundation · Build Better Health Habits · Leading Under Pressure | | :---:');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('b6cf7c1b-7194-53ad-8fa9-068a643587a4', '3588f039-4d3a-5ef0-a2e1-ebaa7387f7ce', 1, 'What is your one real first step — specific enough that you could describe exactly what you will do and when?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('af2f9bb8-85ea-5a11-9efa-121cf6442dfa', '3588f039-4d3a-5ef0-a2e1-ebaa7387f7ce', 2, 'What would it mean to have taken this step a week from now — what would be different?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('a6328377-f340-52d8-8f02-5961cfe3f7fe', '3588f039-4d3a-5ef0-a2e1-ebaa7387f7ce', 3, 'Who will you tell, and when, so that this becomes a real commitment rather than a private intention?');
INSERT INTO public.path (id, name, description, tier, pillar, "subMode", "sessionsCount", classifications, "triggerSignals") VALUES ('d23ea3a4-4a6c-5b34-87b7-c07304b018ad', 'Foundations of a Balanced Life', 'Health and Wellness  ·  General Health  ·  Alignment Fracture · Building Momentum', 'free', 'health', 'general_health', 5, 'Alignment Fracture · Building Momentum', 'enrollment:onboarding; flag:None — all users matching classification');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('ef053b37-1468-5224-87d0-f768050c40c4', 'd23ea3a4-4a6c-5b34-87b7-c07304b018ad', 1, 'What balance actually looks like in a real life', 'Balance is one of those words that sounds simple and means something different to almost everyone who uses it. When most people say they want more balance, what they usually mean is: I want to feel less like I am failing at half my life while barely surviving the other half. That is a reasonable thing to want. But the word balance can make it sound like the goal is an equal distribution of time and energy across all domains, maintained with perfect consistency. That version of balance does not exist in a real life, and pursuing it tends to create more guilt than peace. What balance actually looks like in a real life is more like this: a set of commitments and priorities that feel genuinely chosen rather than just accumulated; enough attention to the things that matter most that they are not being neglected to the point of damage; and enough recovery built into the rhythm of the week that you are not constantly running at a deficit. Balance in a real life is not static. It shifts with seasons, with demands, with age, with what matters. What balance looked like five years ago may not be what it looks like now. The goal is not to find the one perfect configuration and lock it in. The goal is to be honest, regularly, about whether the current configuration is working — and to make adjustments before the gaps become crises.', 'This week: write your honest definition of balance for your current life. Not someone else''s version. Yours.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('36d2072c-9d90-5f23-ba14-5eca6a27e484', 'ef053b37-1468-5224-87d0-f768050c40c4', 1, 'When you say you want more balance, what specifically are you missing right now — what is too much, and what is getting too little?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('7cbab969-fcc1-55f4-bafc-ac3c76faf340', 'ef053b37-1468-5224-87d0-f768050c40c4', 2, 'What does your version of balance actually look like — not the ideal version, but the realistic one for your specific life?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('9a09b182-1efe-5bfd-ba72-9ad87d724514', 'ef053b37-1468-5224-87d0-f768050c40c4', 3, 'What would need to shift — even slightly — for your life to feel more genuinely balanced this week?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('d999799b-6fdf-5b04-ab60-2c632edf1296', 'd23ea3a4-4a6c-5b34-87b7-c07304b018ad', 2, 'The three non-negotiables for basic wellbeing', 'Before you can build anything more sophisticated, there are three foundational inputs that must be present at a minimum level. Without these three things, everything else is built on an unstable base — your capacity for work, for relationship, for presence, for managing stress — all of it degrades when these basics are absent. The three are sleep, movement, and something that nourishes you — whether that is food, connection, time in nature, creative expression, or whatever genuinely fills rather than depletes you. These are not luxuries. They are the infrastructure of human functioning. Every other wellness goal, every habit, every ambition — all of it is easier and more sustainable when these three things are in place. Most people in a season of imbalance have allowed one or more of these three to collapse. The sleep got shorter because there was not time. The movement disappeared because something else took its slot. The nourishing thing stopped happening because it felt like an indulgence when there was so much else to do. The work of this path begins with these three because everything else builds on them. Not perfectly — at minimum viable levels. What does enough sleep look like? What does the most basic movement that you will actually do look like? What is the smallest version of nourishment that counts?', 'This week: choose the one foundational input that is most depleted and take one concrete step to stabilize it.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('0206442d-f960-52b9-884e-e618d560e0b8', 'd999799b-6fdf-5b04-ab60-2c632edf1296', 1, 'Which of the three — sleep, movement, nourishment — is most compromised right now, and what has pushed it out?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('bc18823c-6b0d-5bd8-9685-d8960f7a4117', 'd999799b-6fdf-5b04-ab60-2c632edf1296', 2, 'What is the minimum viable version of each that would give your system something to work with?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('4d9583f3-56ac-5a7f-9152-f9a580dbca4e', 'd999799b-6fdf-5b04-ab60-2c632edf1296', 3, 'If you could only stabilize one of the three this week, which one would have the highest impact on everything else?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('1c6100e8-95b6-5986-b9bb-a8c5dd492f53', 'd23ea3a4-4a6c-5b34-87b7-c07304b018ad', 3, 'Identifying what is most off right now', 'Balance is not maintained by attending equally to everything. It is maintained by honest triage — by being clear-eyed about where the most significant gaps are and addressing those first, rather than spreading thin attention across every domain simultaneously. The honest triage question is this: if you look across the major areas of your life — your health, your work, your relationships, your rest, your sense of meaning — where is the gap costing you the most right now? Not the area with the most room for improvement. The area where the current state is creating the most damage or the most drain. This question requires honesty, because the area that is costing the most is often not the most comfortable one to look at. It is usually the one that has been pushed aside longest — the one where you tell yourself things are fine when some part of you knows they are not. Triage does not mean abandoning everything else. It means deciding where your limited energy for change will have the most impact, and directing it there deliberately rather than diffusing it across everything at once.', 'This week: name the one area that is most off. Write what good enough would look like in that area. Take one step toward it.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('28c54a9e-7862-5a55-ae23-5823c2ddbe0c', '1c6100e8-95b6-5986-b9bb-a8c5dd492f53', 1, 'If you look honestly across the major areas of your life, where is the gap costing you the most right now?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('475fa844-cea7-5e96-a954-5b85cb151fcd', '1c6100e8-95b6-5986-b9bb-a8c5dd492f53', 2, 'Why has that area been the one to slip — what made it easier to let that one go than others?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('a4dbb487-5c1b-58ac-9ad9-c294ccd1c76c', '1c6100e8-95b6-5986-b9bb-a8c5dd492f53', 3, 'What would it look like to give that area even a small amount of deliberate attention this week?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('da3c6a94-e731-58eb-8e10-51bbf6d4dbb2', 'd23ea3a4-4a6c-5b34-87b7-c07304b018ad', 4, 'One thing to stabilize this week', 'Everything in this path is building toward a version of change that is small enough to actually happen. Not a life overhaul. Not a new system. Not the aspirational schedule you have designed and abandoned before. One thing. This week. That actually gets done. The one thing should meet three criteria. It should address something that is genuinely off — not just a nice-to-have improvement but something whose absence is actually costing you. It should be specific enough that you know exactly what you are doing and when you are doing it. And it should be small enough that the friction of starting it is lower than the cost of continuing to ignore it. The purpose of the one thing is not to solve the imbalance. The imbalance has accumulated over time and will resolve over time. The purpose is to create one piece of evidence — for yourself — that deliberate change is possible. That you can identify something that needs attention and actually attend to it. That small action is available to you even when the overall situation feels too large to address. One piece of evidence becomes two. Two becomes a pattern. A pattern becomes a different life.', 'This week: do the one thing. Every day if it is daily. Once if it is weekly. Track it simply — a check mark. That is enough.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('73f9f430-417f-5446-aca6-2fdf6a26af5f', 'da3c6a94-e731-58eb-8e10-51bbf6d4dbb2', 1, 'What is the one thing you will stabilize this week — specific, small, and genuinely needed?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('5c9d0535-4358-5969-ba24-bc394a515cd7', 'da3c6a94-e731-58eb-8e10-51bbf6d4dbb2', 2, 'What would make it most likely to actually happen — what time, what context, what prior commitment?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('32153882-086d-5cd5-a32e-31f8aaf94f4d', 'da3c6a94-e731-58eb-8e10-51bbf6d4dbb2', 3, 'What would need to be different for this one thing to still be happening four weeks from now?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('ec7042ff-b33a-56db-a290-239b0d0b7678', 'd23ea3a4-4a6c-5b34-87b7-c07304b018ad', 5, 'What a good day looks like for you', 'Most people spend very little time thinking concretely about what a good day actually looks like for them — specifically, for their particular life, their particular values, their particular needs. They have a vague sense that things should feel better than they do, but they have not defined what better actually looks like in practice. Defining a good day is not about designing the perfect life. It is about getting clear enough on what actually matters that you can recognize when you are moving toward it and when you are moving away from it. Without that clarity, it is easy to make a hundred small decisions that collectively produce a life that looks fine but does not feel like yours. A good day does not require everything to go right. It requires that a handful of things be present — things specific enough that you know when they happened and when they did not. A conversation with someone who matters. Time doing something that uses your actual skills. A moment of genuine rest. Some form of movement. Food that sustains rather than just occupies. Connection with something that reminds you why the whole thing matters. What are your things? Not in general — specifically. The ones that make the difference between a day that felt like it was worth living and a day that just passed.', 'Closing commitment: Design tomorrow. Intentionally. Around your definition of a good day. Notice whether it lands differently. |');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('5188fef7-1022-598f-908a-133222bca8f4', 'ec7042ff-b33a-56db-a290-239b0d0b7678', 1, 'What are the specific things that, when present, make a day feel genuinely good for you — your actual things, not generic ones?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('20e7db2d-899b-5fec-a17b-8d6c19cf8701', 'ec7042ff-b33a-56db-a290-239b0d0b7678', 2, 'What has been consistently absent from your days recently that, when present, would make them feel meaningfully better?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('e189a083-7bf2-5cfe-a0ed-a11c491ccc91', 'ec7042ff-b33a-56db-a290-239b0d0b7678', 3, 'What would tomorrow look like if you designed it around your actual definition of a good day rather than just responding to what comes?');
INSERT INTO public.path (id, name, description, tier, pillar, "subMode", "sessionsCount", classifications, "triggerSignals") VALUES ('a144fb82-a164-58a1-b777-d756b88785ec', 'Building Daily Structure', 'Health and Wellness  ·  General Health  ·  Capacity Erosion · Alignment Fracture', 'free', 'health', 'general_health', 6, 'Capacity Erosion · Alignment Fracture', 'enrollment:onboarding; flag:None — all users matching classification');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('73ebb1a3-da7a-50d1-9c7e-e76b2562352a', 'a144fb82-a164-58a1-b777-d756b88785ec', 1, 'Why structure matters when everything feels loose', 'When life feels chaotic or depleted, structure is one of the first things that dissolves — and one of the last things that gets rebuilt, because rebuilding it requires the same energy that its absence is draining. This is one of the cruelest features of difficult periods: the thing you most need to function is the thing you are least able to create when you need it most. Structure matters not because it makes you more productive in a conventional sense — though it often does — but because it provides something the nervous system genuinely needs: predictability. When the nervous system knows what is coming next, it can afford to relax slightly. When everything is uncertain and reactive, the system stays in a state of low-grade vigilance that is exhausting over time. The structure you need is not a rigid schedule or a perfectly optimized routine. It is enough predictability to reduce the sense of free-fall. Enough rhythm to give the day some shape. Enough consistency in a handful of anchors that the nervous system has something reliable to rest on. Structure is not about discipline. It is about giving your system the conditions it needs to function. When the conditions are right, functioning follows.', 'This week: identify the two or three anchors that, if consistent, would give your day the most shape. Write them down.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('64f84e95-c78e-5501-8653-809785ce3b52', '73ebb1a3-da7a-50d1-9c7e-e76b2562352a', 1, 'What has dissolved from your daily structure recently — what rhythms or routines are no longer happening?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('0c4dce3f-76f4-5d5d-bb86-e07486f5cc0a', '73ebb1a3-da7a-50d1-9c7e-e76b2562352a', 2, 'What is the effect of that dissolution on how you feel day to day — what does the looseness cost you?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('8613ab90-65fc-5e0b-b7b3-793e2cdc9be6', '73ebb1a3-da7a-50d1-9c7e-e76b2562352a', 3, 'When you have had more structure in the past, what specifically made the difference — what were the key anchors?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('8613cb9c-f33a-50cc-ba5b-b8963b780481', 'a144fb82-a164-58a1-b777-d756b88785ec', 2, 'The minimum structure that actually holds', 'The most common mistake in rebuilding daily structure is starting with too much. The aspirational schedule — with its morning pages and meditation and workout and deep work block and healthy lunch and afternoon walk and evening wind-down routine — is not the problem. The problem is that it was designed by your best-case self for your best-case day, and it collapses completely on the inevitable average day. Minimum viable structure is not a compromise. It is the foundation. It is the set of things that are simple enough, consistent enough, and small enough that they hold on the hard days — not just the good ones. The good days will take care of themselves. The hard days need structure that is built for hard days. What does minimum viable structure look like? It usually has three components: a consistent start, a consistent midpoint anchor, and a consistent end. The start does not have to be early or dramatic. It needs to be consistent. The midpoint anchor — a meal, a walk, a brief check-in with yourself — marks the middle of the day and interrupts the drift. The end signals that the day is closing and allows the system to downregulate. Three anchors. Not ten. Three. If you can hold three consistently, you have the foundation on which everything else becomes possible.', 'This week: implement your three anchors — start, midpoint, end. Keep them simple. Do them every day. Track them with a check mark.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('70c10d2c-dc4c-5a25-9350-36eb053b31a2', '8613cb9c-f33a-50cc-ba5b-b8963b780481', 1, 'What is the simplest version of a daily start, midpoint, and end that you could realistically maintain even on the hardest days?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('f7bae891-0012-5088-bbf5-397859200380', '8613cb9c-f33a-50cc-ba5b-b8963b780481', 2, 'Where does your current daily structure most reliably fall apart — which part of the day goes most off-script?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('483d5ebd-cbdd-50a4-b0ee-bec65f696ac7', '8613cb9c-f33a-50cc-ba5b-b8963b780481', 3, 'What one change to the structure of your day would have the most stabilizing effect?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('8917ec65-cffa-543d-bdfb-f72b9c6358d0', 'a144fb82-a164-58a1-b777-d756b88785ec', 3, 'Morning anchors — what to do before the day takes over', 'The morning is the part of the day when you have the most agency. Before the emails arrive, before the requests come in, before the day asserts its own agenda — there is a window. It may be five minutes. It may be an hour. Whatever its length, it is yours in a way that the rest of the day often is not. How you use that window sets the tone for everything that follows. Not because the morning is magic, but because the habits and intentions you establish before the day''s demands arrive tend to persist longer than the ones you try to establish in the middle of the noise. A morning anchor is not a complex routine. It is one consistent thing — something that takes under ten minutes, happens at the same time, and signals to your nervous system that you are in control of the beginning of your day rather than immediately reactive to it. It might be five minutes of deliberate silence before looking at your phone. It might be a brief piece of writing — one sentence about what matters today. It might be movement. It might be something you eat at the same time every morning. The specific content matters less than the consistency and the sequence. Something you do before the day takes over, every day, without exception.', 'This week: establish your morning anchor. One thing. Before you check your phone. Every day. No exceptions.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('11521a87-1c6f-5013-a00e-1de822c959d4', '8917ec65-cffa-543d-bdfb-f72b9c6358d0', 1, 'What currently happens in the first thirty minutes of your day — who or what is in control of that window?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('fdd66514-28b4-583f-9da2-49143b06174e', '8917ec65-cffa-543d-bdfb-f72b9c6358d0', 2, 'What would a realistic morning anchor look like for you — something under ten minutes that you could actually do every day?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('0eb72016-2ef5-5c15-ba28-7555dac53d1a', '8917ec65-cffa-543d-bdfb-f72b9c6358d0', 3, 'What would you have to change about your current morning for that anchor to be possible?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('62103e33-3d2c-5b6f-95e9-553e62847f4f', 'a144fb82-a164-58a1-b777-d756b88785ec', 4, 'Evening routines that do not require perfection', 'The evening is the part of the day most people try to optimize last and abandon first. It gets colonized by whatever the day left undone, by screens and stimulation, by the exhaustion that makes anything requiring decision-making feel impossible. And yet the evening is where sleep quality is largely determined — which means it has an outsized effect on every hour of the following day. An evening routine does not require perfection, a specific bedtime, or a complete wind-down protocol. It requires one consistent signal to your nervous system that the day is ending. One thing that marks the transition from on to off. One practice that is consistent enough that the body begins to recognize it as the beginning of rest. This might be as simple as stopping looking at screens thirty minutes before sleep. It might be a brief piece of writing that closes the day — what happened, what you are grateful for, what you will leave until tomorrow. It might be a cup of tea at the same time every night. Something consistent. Something that is yours. The purpose of the evening signal is not to eliminate all stimulation before sleep. The purpose is to create a recognizable marker that tells your system: the active part of the day is over. You can begin to let go.', 'This week: implement one evening signal. Do it at the same time every night. Notice whether your sleep quality shifts.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('3a9e4fd2-cb9b-5e9f-99ad-ac5d1a5d2007', '62103e33-3d2c-5b6f-95e9-553e62847f4f', 1, 'What does your evening currently look like — what happens between dinner and sleep?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('a165f199-0d58-5c6c-9989-65e6a3311d15', '62103e33-3d2c-5b6f-95e9-553e62847f4f', 2, 'What is one simple, realistic evening signal that would help your nervous system recognize that the day is ending?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('da9b66c9-8ab0-5294-8934-aeb9bc1bccf9', '62103e33-3d2c-5b6f-95e9-553e62847f4f', 3, 'What would you have to remove or reduce in the hour before sleep to make that signal more effective?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('32a3f8a1-f216-5019-8cec-5ce6f359bae9', 'a144fb82-a164-58a1-b777-d756b88785ec', 5, 'Building consistency without rigidity', 'There is a difference between consistency and rigidity, and it matters for whether your structure survives contact with real life. Rigidity is structure that works only when everything goes according to plan. Consistency is structure that holds well enough even when things do not go according to plan. The rigid structure says: if I miss my morning run, the whole day is ruined and there is no point in trying. The consistent structure says: I missed my morning run today. I will do something shorter in the afternoon. The practice continues. The critical skill in building sustainable daily structure is the return — the ability to pick up after a disruption without treating the disruption as evidence of failure. Disruptions are guaranteed. They are not evidence that the structure does not work. They are evidence that life is variable and structure has to be resilient enough to absorb variability. What makes structure resilient is not perfection in the design. It is flexibility in the execution, combined with a commitment to return that does not require starting over. The structure bends. It does not break. You miss a day, and you do not make that mean anything other than: I missed a day. And you return.', 'This week: plan your disruption response. Write what you will do when you miss a day. Practice returning without drama.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('9eba6502-4fcd-5029-8700-a25e7fd94d06', '32a3f8a1-f216-5019-8cec-5ce6f359bae9', 1, 'What is your current pattern when your structure breaks down — what do you do, and what story do you tell yourself?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('c3372354-0764-5c78-a24e-74b28ce34ed7', '32a3f8a1-f216-5019-8cec-5ce6f359bae9', 2, 'What would it look like to have a resilient response to disruption — one that keeps the structure intact without requiring perfection?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('1364c934-34b4-5bbd-897f-6ca17e1189c5', '32a3f8a1-f216-5019-8cec-5ce6f359bae9', 3, 'What is the most common disruption to your daily structure, and how could you build a planned response to it?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('53d12b2c-41d8-5eb9-ae4c-af7cca998c8a', 'a144fb82-a164-58a1-b777-d756b88785ec', 6, 'What to do when the structure falls apart', 'Structure falls apart. This is not a hypothesis — it is a certainty. There will be weeks when the morning anchor disappears, the evening routine collapses, and the days lose their shape entirely. This happens to everyone who has ever tried to build something consistent in a real life. The question is never whether it will happen. The question is what you do when it does. The most common response is to treat the collapse as a signal that structure does not work for you, or that you are not capable of maintaining it, or that the whole attempt was misguided. This response turns a temporary disruption into a permanent abandonment. The next attempt starts from scratch, with the same aspirational design, and collapses in the same way — which produces more evidence for the same conclusion. The more useful response is to treat the collapse as a temporary weather event rather than a structural failure. The structure is sound. The conditions were difficult. When the conditions improve — when the crisis passes, when the travel ends, when the demanding week is over — the structure resumes. Not a new structure. The same structure. Picked up where it was left. This is the skill that distinguishes people who build lasting daily structure from those who remain in a cycle of designing and abandoning. Not the quality of the design. The quality of the return.', 'Closing commitment: Write your return practice. When the structure falls apart, I will do this: \[specific action\]. Keep it simple. One sentence. |');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('e79e5f79-a9c1-5833-b28a-0e6061c4508a', '53d12b2c-41d8-5eb9-ae4c-af7cca998c8a', 1, 'When was the last time your daily structure completely fell apart, and what happened next — did you return, and if so, how?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('5ce2c2c0-583a-56e6-8421-69642c343df7', '53d12b2c-41d8-5eb9-ae4c-af7cca998c8a', 2, 'What do you need to believe about the collapse in order to return to the structure without starting over from scratch?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('cc64f09f-09ef-54ea-9ba1-1f247390d1b5', '53d12b2c-41d8-5eb9-ae4c-af7cca998c8a', 3, 'What does your return practice look like — the specific thing you do on the first day back after a disruption?');
INSERT INTO public.path (id, name, description, tier, pillar, "subMode", "sessionsCount", classifications, "triggerSignals") VALUES ('1a8cb2d4-5678-50aa-988b-111437a5baca', '30-Day Foundation', 'Health and Wellness  ·  Recovery and Sobriety  ·  Any classification  ·  Requires recovery_mode_active \= yes', 'pro', 'health', 'recovery_and_sobriety', 10, 'Any classification', 'enrollment:onboarding; flag:Requires recovery_mode_active \= yes');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('70d7915b-b839-5c6e-b73d-6001eed426a4', '1a8cb2d4-5678-50aa-988b-111437a5baca', 1, 'Day 1 — why you are here and what you are actually building', 'You made a decision to be here. That decision may have been easy or it may have been the hardest thing you have done. Either way, you made it. And the fact that you are here — on day one, or whatever day this actually is for you — is the only thing that has to be true right now. This path is not going to tell you what recovery should look like, or pressure you toward any particular program or philosophy. Recovery is not one-size. What it looks like for you will be shaped by you — by your history, your circumstances, your support, and what you need. What this path offers is structure and accompaniment for the first thirty days. Thirty days is not a finish line. It is not the point at which recovery is complete or the work is done. It is a foundation — enough of a foundation that what comes after has something solid to stand on. Day one to day thirty is about building one thing: the evidence, in your own life, that thirty days is possible. Because if thirty is possible, sixty is imaginable. And if sixty is imaginable, you can begin to picture a life. You do not need to picture a life today. You need today. That is all.', 'Your commitment for today: I am here. I am starting. Today is day one. That is enough.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('79049ae4-3e6a-5806-b6a4-aa6d396414a9', '70d7915b-b839-5c6e-b73d-6001eed426a4', 1, 'What brought you to this path today — not the whole story, just what made today the day?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('160eb56e-400b-55ad-9b33-fc54efca12d1', '70d7915b-b839-5c6e-b73d-6001eed426a4', 2, 'What do you want the next thirty days to look like — not perfectly, but honestly?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('9c5cd190-8afc-5231-87e8-5e04587e2c91', '70d7915b-b839-5c6e-b73d-6001eed426a4', 3, 'What is the single most important thing you need to protect or build in order to get through the first week?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('82d9e421-c452-5e3d-9b33-627641e784bf', '1a8cb2d4-5678-50aa-988b-111437a5baca', 2, 'Building your daily check-in habit', 'Recovery needs a daily practice of honest self-assessment — not because you are being monitored, but because the distance between where you are and where your patterns want to take you can close very quickly when you stop paying attention. The daily check-in is how you stay close to yourself. A daily check-in does not have to be elaborate. It can be three questions answered in writing, or out loud to yourself, or to someone you trust. How am I feeling right now — physically, emotionally, and in terms of my recovery? What is my risk level today — are there situations, emotions, or circumstances that are elevated? And what is my one commitment for today? The value of the check-in is not in any individual day''s answers. It is in the accumulated pattern — the ability to look back over a week and see what your state has been, where the risk has concentrated, and whether the commitments have held. That pattern is information. It tells you things about your recovery that you cannot see when you are inside any single day. The check-in also builds the habit of honest self-reporting — of telling yourself the truth about where you are rather than the comfortable story. In recovery, honest self-reporting is one of the most protective practices available.', 'This week: do your daily check-in every day. Three questions. Written or spoken. Same time each day.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('3db5ac66-d1ce-5f5c-a70b-463f970a7ed9', '82d9e421-c452-5e3d-9b33-627641e784bf', 1, 'What does honest self-assessment look like for you — what are the questions you most need to ask yourself daily?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('33f83933-273f-5404-89d4-fb6bf2656e9a', '82d9e421-c452-5e3d-9b33-627641e784bf', 2, 'What time of day and what context would make a daily check-in most realistic for your life?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('6030468f-7162-5b78-a307-212bc72b288c', '82d9e421-c452-5e3d-9b33-627641e784bf', 3, 'Who, if anyone, could you share your daily check-in with — someone who would hold the practice with you?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('9c034b97-8979-5944-9304-76be5fab8249', '1a8cb2d4-5678-50aa-988b-111437a5baca', 3, 'Identifying your highest-risk moments', 'Not all moments in recovery are equally risky. There are specific times, situations, emotions, and contexts that consistently create more vulnerability — that bring you closer to the point where the pull is strongest. Knowing your personal high-risk moments is one of the most protective things you can do, because you can prepare for them in advance rather than encountering them unprepared. High-risk moments are personal and specific. For some people they are times of day — late evening, when the day is done and the quiet is loud. For some they are emotional states — loneliness, boredom, anger, or the particular kind of exhaustion that makes everything feel pointless. For some they are social contexts — specific places, specific people, specific combinations of circumstance. For some they are physiological — hungry, tired, in pain. The acronym HALT is worth knowing: Hungry, Angry, Lonely, Tired. These four states, alone or in combination, significantly increase vulnerability in recovery. They are not warnings to avoid — they are unavoidable human experiences. But they are moments to pay attention to, to have a plan for, to bring extra support to. Your risk map is yours. The goal is not to eliminate every high-risk moment — that is not possible. The goal is to know where they are so you can move through them with more support and more intention.', 'This week: map your high-risk moments. Write them down. Make a plan for the highest-risk one. Have it ready before you need it.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('8e5e8b42-3dca-5b59-93cb-2dfd2c9ae476', '9c034b97-8979-5944-9304-76be5fab8249', 1, 'What are your specific high-risk moments — when, where, and under what conditions does the pull tend to be strongest?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('6d153bbe-d7eb-5ff0-8ce8-2620ce222c4d', '9c034b97-8979-5944-9304-76be5fab8249', 2, 'Of those moments, which one is most predictable and most frequent — the one you are most likely to encounter this week?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('3391ef5c-510f-5684-884f-b9202c75ca81', '9c034b97-8979-5944-9304-76be5fab8249', 3, 'What is your plan for that specific moment — what will you do, who will you contact, what will you tell yourself?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('48298ebd-c82d-572f-a9ee-763b1e916062', '1a8cb2d4-5678-50aa-988b-111437a5baca', 4, 'Coping tools that actually work for you', 'Generic coping tools are everywhere. Deep breathing, grounding exercises, calling your sponsor, going to a meeting — these are real tools and they help many people. But the most effective coping tools are the ones that are calibrated to how you specifically experience the pull, what your body and mind actually need in those moments, and what you can realistically access when things are hard. This means building your personal coping toolkit through honest experimentation. What actually helps when the craving hits? Not what should help in theory — what has actually helped, even slightly, in moments when the pull was strong? What interrupted the cycle? What gave you enough space to not act on it? Some tools work in the moment — physical interruption, breath, movement, cold water, calling someone. Some work in the hours before — filling the high-risk window with structure, connection, or an activity that makes acting on the pull logistically harder. Some work in the recovery afterward — the practice of returning to your commitment without catastrophizing after a difficult moment. Your coping toolkit should have tools for each phase: before the peak, during the peak, and after. And the most important tool is the one you will actually use — not the most sophisticated one, the most accessible one.', 'This week: identify your three most reliable coping tools. Practice one of them today, before you need it.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('dc826367-bc53-519e-9c4c-6ecb8e924dd1', '48298ebd-c82d-572f-a9ee-763b1e916062', 1, 'What has actually helped you get through difficult moments in the past — what has interrupted the cycle even briefly?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('b8a4937e-d5b2-56bd-87e7-3234accb1528', '48298ebd-c82d-572f-a9ee-763b1e916062', 2, 'What coping tool is most reliably accessible to you in the moments when it is hardest — the one you can always reach for?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('1cfbe93c-1ca6-5839-b44d-cb7adbe2a752', '48298ebd-c82d-572f-a9ee-763b1e916062', 3, 'What coping tool do you need to add or strengthen — what gap exists in your current toolkit?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('f0c7d98d-266c-557e-b523-b8ccbd848ba0', '1a8cb2d4-5678-50aa-988b-111437a5baca', 5, 'Navigating social situations in early recovery', 'Early recovery and social situations have a complicated relationship. Social connection is one of the most powerful supports for recovery — and social contexts can also be among the highest-risk environments, particularly when they involve alcohol, substances, or people from your using history. Navigating this requires a kind of honest advance planning that most people find uncomfortable because it requires acknowledging, in advance, that social situations are not neutral. They have a risk level. And managing that risk level thoughtfully — deciding what to attend, what to skip, how long to stay, what your exit plan is — is not antisocial. It is smart. Some principles that help: you do not have to explain your recovery to everyone. ''I am not drinking tonight'' is a complete sentence that most people will accept without further inquiry. You do not have to attend every social event during early recovery. Protecting your recovery is a legitimate reason to decline invitations. And having a plan for how you will handle an unexpected high-risk moment in a social context — including permission to leave — is preparation, not weakness. You are building something. The social world can wait, or be navigated carefully, while you build it.', 'This week: identify one upcoming social situation and make a specific plan for it. Entry, exit, what you will say, who you will call if needed.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('204604da-1e2f-5c7f-bbdf-0bf02566c304', 'f0c7d98d-266c-557e-b523-b8ccbd848ba0', 1, 'What social situations in the coming weeks are potentially high-risk for your recovery?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('faad3f24-310e-50d4-8f76-66fc8c31c463', 'f0c7d98d-266c-557e-b523-b8ccbd848ba0', 2, 'What is your plan for those situations — attend with a plan, decline, or something else?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('bd1ab5de-6646-50e8-9cfc-85b0d864d06b', 'f0c7d98d-266c-557e-b523-b8ccbd848ba0', 3, 'What do you need to be willing to say or do in a social context to protect your recovery, even if it is uncomfortable?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('0805e55a-9243-5fe2-bd9c-6ce3d465b629', '1a8cb2d4-5678-50aa-988b-111437a5baca', 6, 'When it gets harder — using support before you break', 'The moment to reach for support is not when you have already relapsed. It is not when you are at the absolute peak of the pull and barely holding. The moment to reach for support is earlier — when things are getting harder, when the risk is elevated, when you can feel the pressure building. Most people wait too long. They tell themselves they can manage it, that they do not want to bother anyone, that it is not bad enough yet to warrant asking for help. And then it is bad enough, and asking for help in that moment is significantly harder than it would have been an hour earlier. Reaching for support before you break requires two things: the self-awareness to recognize when the pressure is building before it peaks, and the permission to ask for help without having reached a crisis point. Both of these are skills that develop through practice. The first time you call someone because you are at a six out of ten and not waiting for a nine, it will feel strange — like you are being dramatic or weak. You are not. You are using support correctly. The purpose of your support network is not to catch you after a fall. It is to walk alongside you so that the fall is less likely. Use it that way.', 'This week: reach out to one person in your support network — not in crisis, just in contact. Let them know how you are actually doing.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('d0bab9b2-ffea-53a9-8a2c-44fc2dc57220', '0805e55a-9243-5fe2-bd9c-6ce3d465b629', 1, 'What are the early signs that things are getting harder for you — the signals that appear before you are in crisis?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('2609be29-eafb-5cde-8693-56e9e7ba4757', '0805e55a-9243-5fe2-bd9c-6ce3d465b629', 2, 'What stops you from reaching for support early — what makes you wait longer than you should?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('9195b3a3-d21b-5a5b-be98-e3f24c14aaa6', '0805e55a-9243-5fe2-bd9c-6ce3d465b629', 3, 'Who specifically will you contact the next time you notice those early signs, and what will you say?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('08292886-2924-5de1-b304-fded5fc2a27c', '1a8cb2d4-5678-50aa-988b-111437a5baca', 7, 'The halfway point — what is working, what is not, what to adjust', 'You are at the halfway point of this path. Thirty days total, and you are somewhere in the middle. This is a good moment to pause and assess honestly — not to judge the progress, but to see it clearly. What has been working? Not what you planned would work — what has actually worked. What tools have you actually used? What practices have held? What moments of strength have surprised you? These are worth naming specifically, because the evidence of your own capability is one of the most powerful things available to you in recovery. What has not been working? Where have the gaps been? Not to assign blame or add to discouragement, but to see clearly so you can adjust. The plan that was designed at the beginning of this path was the best guess available then. You have more information now. Adjustment is not failure — it is intelligent response to evidence. And what do you need for the second half? More support, more structure, more tools, more honesty with someone specific, a different approach to a particular high-risk situation? The second fifteen days build on what you have learned in the first fifteen.', 'This week: write your halfway assessment. What worked. What did not. What you are adjusting. Be specific and honest.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('17f29a44-afb3-5ae0-b6c6-dd0820741e13', '08292886-2924-5de1-b304-fded5fc2a27c', 1, 'What has actually worked in your recovery so far — what specific practices, tools, or moments of strength stand out?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('19028006-2123-5791-894e-642153033be6', '08292886-2924-5de1-b304-fded5fc2a27c', 2, 'Where have the gaps been — what has not worked as you hoped, and what do you need to adjust?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('53e108ad-dff8-5301-aa2b-9901df140fb2', '08292886-2924-5de1-b304-fded5fc2a27c', 3, 'What do you need for the second half of this path that you did not have at the beginning?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('80569797-e13a-5c43-9e40-a6d0394cc5b1', '1a8cb2d4-5678-50aa-988b-111437a5baca', 8, 'Physical recovery — sleep, movement, nutrition as recovery tools', 'Recovery is not only psychological. It is physiological. The brain and body that carried the weight of addiction have real physical work to do in recovery — rebalancing neurochemistry, restoring sleep architecture, rebuilding physical health that may have been neglected. Attending to the physical dimension of recovery is not separate from the work of recovery. It is part of it. Sleep is often the most disrupted and most important. Disrupted sleep in early recovery is extremely common — the brain''s sleep systems take time to rebalance. Prioritizing sleep hygiene, protecting sleep time, and being patient with the process of sleep normalizing is important work. Movement — whatever form works for your body and your current capacity — is one of the most well-supported tools for supporting recovery neurologically. It reduces cravings, improves mood, reduces anxiety, and supports the sleep system. It does not need to be intense. It needs to be regular. Nutrition in recovery can be complicated by appetite changes, by the habits that were built around use, and by the reality of limited energy for cooking or planning. But even small improvements — more water, more protein, less processed sugar — support the physical recovery process. Start where you actually are, not where you think you should be.', 'This week: make one change in each area — one sleep improvement, one movement practice, one nutritional choice. Small and real.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('da874201-75f6-5a64-96ae-6fd0a2f8db13', '80569797-e13a-5c43-9e40-a6d0394cc5b1', 1, 'How is your sleep right now — is it improving, still disrupted, or something you have not been paying attention to?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('baa4468f-e967-5101-b968-0ca56c3c6bc7', '80569797-e13a-5c43-9e40-a6d0394cc5b1', 2, 'What form of movement is most realistic and sustainable for you right now — something you could do three or four times this week?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('61dac620-182a-5f14-8060-ba01e8fac647', '80569797-e13a-5c43-9e40-a6d0394cc5b1', 3, 'What is the one nutritional change that would be most supportive of your recovery and most realistic to actually make?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('cdff4baf-a683-57a5-8960-53b5c70e5079', '1a8cb2d4-5678-50aa-988b-111437a5baca', 9, 'Rebuilding relationships one honest conversation at a time', 'Recovery affects relationships. The use affected relationships, and the recovery affects them differently. Some people in your life are relieved and supportive. Some are still processing what the use meant for them. Some are cautious, not yet sure whether to trust the change. Some are in their own complicated relationship with substances and may not be safe for your recovery. Rebuilding relational trust is slow work. It is done through consistency over time — through being someone who does what they say, who shows up when they said they would, who is honest when honesty is hard. Trust is rebuilt through accumulation, not through dramatic gestures or single conversations. The honest conversations are important, but they need to be well-timed. Not every person needs a formal conversation about the past or the future. Some relationships will rebuild naturally through time and consistent behavior. Others need explicit acknowledgment — not necessarily a full accounting, but some honest recognition of what happened and what is different now. The conversations happen one at a time, when you have the capacity for them, when the relationship is ready for them. Recovery does not require solving everything with everyone at once. It requires moving in the right direction — with honesty, with consistency, with care.', 'This week: identify one relationship you want to tend. Take one consistent, small action toward it. Show up in a way that builds evidence.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('155ce6c9-4084-58b3-8558-be2c8b694e71', 'cdff4baf-a683-57a5-8960-53b5c70e5079', 1, 'Which relationships feel most in need of attention right now — where is the trust most in need of rebuilding?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('95388945-6f0d-54fd-8e6e-db89bc2d3f24', 'cdff4baf-a683-57a5-8960-53b5c70e5079', 2, 'What does rebuilding trust in those relationships actually look like — what specific behaviors, over what timeframe?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('f9fa6faf-5ab4-5de0-98c6-3b1246a89dff', 'cdff4baf-a683-57a5-8960-53b5c70e5079', 3, 'Is there one conversation that needs to happen — not a full accounting, but one honest thing said to one person?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('89716e3f-664f-5169-b948-2586eea32459', '1a8cb2d4-5678-50aa-988b-111437a5baca', 10, 'Day 30 — what you have built and what comes next', 'Thirty days. You have arrived at the end of this path, which is also the beginning of everything that comes after it. What you have built in thirty days is not a perfect record. It is not the absence of difficulty or the complete resolution of craving. It is something more durable than that: evidence. Evidence, in your own experience, that thirty days is survivable. That the tools work, at least some of the time. That you can reach for support. That a different day is possible — because you have lived some of those different days. Thirty days is not the finish line. For most people it is more like the end of the acute phase — the period of highest intensity, highest risk, and most unfamiliar terrain. The second thirty days will be different. Not necessarily easier, but different. The terrain will be more familiar. Some of the tools will feel more natural. Some of the support will feel more established. What comes next is yours to design. Not all at once — just the next piece. The next thirty days, or the next week, or just tomorrow. The same principle that got you through the first day — just the next thing, just the next stretch of time — continues to work on day thirty-one. You made it through this path. That is real. That matters. You are still here, and you are building something.', 'Closing commitment: Write a letter to yourself from day thirty. What you want to remember. What you are proud of. What you are building toward. Read it on day sixty. |');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('d2633ebc-dde9-5ef5-9872-039530592b89', '89716e3f-664f-5169-b948-2586eea32459', 1, 'What has changed for you over the past thirty days — in your recovery, in yourself, in your understanding of what you need?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('de192dc3-63f5-55a5-b98e-7aac3bd53862', '89716e3f-664f-5169-b948-2586eea32459', 2, 'What are you most proud of from this period — what moment or practice or decision stands out?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('3ff8f845-108b-5436-ae34-b064efdcf9b6', '89716e3f-664f-5169-b948-2586eea32459', 3, 'What does the next chapter of your recovery look like — what are you committing to for the next thirty days?');
INSERT INTO public.path (id, name, description, tier, pillar, "subMode", "sessionsCount", classifications, "triggerSignals") VALUES ('895a0ed5-104a-506f-956b-1ff480b69b61', 'Build Better Health Habits', 'Health and Wellness  ·  General Health  ·  Alignment Fracture · Building Momentum', 'pro', 'health', 'general_health', 8, 'Alignment Fracture · Building Momentum', 'enrollment:onboarding; flag:None — all users matching classification');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('2a7858c1-d0e3-58aa-bdf9-654dfec99d37', '895a0ed5-104a-506f-956b-1ff480b69b61', 1, 'Habit science — what actually makes habits stick', 'Most people fail at building new habits not because they lack willpower or discipline, but because they are trying to build habits in ways that are inconsistent with how habit formation actually works neurologically. Understanding the science is not just interesting — it directly improves the likelihood that the habits you are trying to build will actually stick. Habits form through repetition of a specific sequence: a cue triggers a routine, and the routine produces a reward. The brain learns this sequence through repetition and eventually automates it — the habit becomes something you do with very little conscious decision-making. This automation is what makes habits powerful: they run without requiring the same energy as deliberate choices. The implications for building habits are specific. The cue needs to be consistent and reliable — a time, a place, a preceding behavior that reliably signals the habit. The routine needs to be specific enough to be repeatable. And the reward needs to be immediate enough that the brain makes the connection between the routine and the good thing that followed. Most new habits fail because the cue is vague, the routine is too ambitious, or the reward is too distant. Making the cue specific, the routine small, and the reward immediate is not a compromise. It is the architecture of habits that actually last.', 'This week: design one habit using the cue-routine-reward structure. Write it out specifically. Start it today.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('18213fbd-7875-5c9b-bbac-62981fa6297b', '2a7858c1-d0e3-58aa-bdf9-654dfec99d37', 1, 'Think of a habit you have successfully built in the past. What made the cue, routine, and reward work in that case?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('70ac0ff9-310b-50de-bc5e-5a93fe6f3438', '2a7858c1-d0e3-58aa-bdf9-654dfec99d37', 2, 'What habit have you tried and failed to build most often? Looking at it through this lens, what was missing?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('87882405-604a-5fe9-a154-b810e8d47fcc', '2a7858c1-d0e3-58aa-bdf9-654dfec99d37', 3, 'What health habit do you most want to build, and what would its cue, routine, and reward look like?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('c6f034f6-cb88-5756-a6b4-8badb4782007', '895a0ed5-104a-506f-956b-1ff480b69b61', 2, 'Auditing your current habits honestly', 'Before building new habits, it helps to see clearly what you are already doing — the full picture of your current health habits, without the filter of what you think they should be. The honest audit is not a judgment. It is a starting point. Current habits are the product of decisions made at various points under various conditions — some of them deliberate, many of them default. They reflect what was easy, what was convenient, what required the least friction in the circumstances you were in. They are not a verdict on your character. They are simply the current state. The honest audit asks: what do you actually eat, on a normal day? How much sleep do you actually get, on most nights? How much movement actually happens, across a typical week? What about stress management — what actually happens when you are stressed? What about rest — what does your recovery time actually look like? This is the data. From the data, you can identify where the largest gaps are between the current state and the direction you want to move. Not the perfect destination — the direction. Which one or two habits, if changed, would create the most meaningful shift in how you feel and function?', 'This week: do your honest audit. Write it down without judgment. Identify your highest-impact gap.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('5decc7f9-0eff-5cd1-a558-be8239ce69ce', 'c6f034f6-cb88-5756-a6b4-8badb4782007', 1, 'What does your current health picture actually look like — sleep, movement, nutrition, stress management — honestly?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('d397f8bf-556d-525d-831e-60bbf018fb4a', 'c6f034f6-cb88-5756-a6b4-8badb4782007', 2, 'Where is the largest gap between your current habits and the direction you want to move?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('8584bada-5872-5aac-940b-d9be171648fd', 'c6f034f6-cb88-5756-a6b4-8badb4782007', 3, 'Which one or two habits, if genuinely changed, would create the most meaningful improvement in how you feel?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('9d39823f-f82d-5f40-ab49-3ef2640179cd', '895a0ed5-104a-506f-956b-1ff480b69b61', 3, 'Starting smaller than feels meaningful', 'The single most common mistake in building health habits is starting too big. The habit that would be meaningful — running five miles, meal prepping for the week, meditating for thirty minutes — is also the habit that collapses under its own ambition after ten days. The brain does not build habits through intensity. It builds them through repetition. And repetition requires starting small enough that the habit can be repeated even on the worst days — even when you are tired, even when you are busy, even when you do not feel like it. Two minutes of movement every day for three weeks builds more lasting habit infrastructure than thirty minutes five days a week for one week. This is not because two minutes produces better fitness outcomes. It is because two minutes has a much higher probability of actually happening every day — which means the neural pathway gets reinforced, which means the habit gets stronger, which means the two minutes gradually and naturally becomes more. The question is not what would be the most impressive habit to build. The question is what is the smallest version of the habit I want that is simple enough that I will actually do it on a hard day. Start there.', 'This week: start the smallest possible version. Not the aspirational version. The version you can do even on a terrible day.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('7247b241-c427-5ab6-b0f9-3a8b187c08a4', '9d39823f-f82d-5f40-ab49-3ef2640179cd', 1, 'What is the smallest possible version of the health habit you want to build — the minimum that still counts?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('d949c782-cd39-519e-abcb-4b8d162e83cf', '9d39823f-f82d-5f40-ab49-3ef2640179cd', 2, 'What is the specific obstacle that has prevented you from sustaining this habit in the past — and does the smaller version remove that obstacle?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('b42b1bab-1f2c-5594-b167-229ecd8ef75c', '9d39823f-f82d-5f40-ab49-3ef2640179cd', 3, 'If you did the small version every single day for thirty days, what would be different about your relationship to this habit?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('2a11ed68-3403-5716-8335-03076170f589', '895a0ed5-104a-506f-956b-1ff480b69b61', 4, 'Sleep as the foundation for everything else', 'Sleep is not one health habit among many. It is the foundation on which every other health habit becomes either possible or impossible. Chronic sleep deprivation degrades cognitive function, emotional regulation, metabolic health, immune function, and the capacity for the kind of sustained effort that building other healthy habits requires. You cannot out-habit a significant sleep deficit. This does not mean that you need to solve your sleep before working on anything else. It means that if your sleep is significantly compromised — less than six hours on most nights, very poor quality, severely disrupted — it deserves priority attention. Not because it is the most glamorous habit, but because improving it will make every other health goal more achievable. What are the highest-leverage changes for sleep quality? Consistency in sleep and wake times matters more than almost anything else — the body''s circadian system is powerful and responds well to regularity. Reducing light exposure in the hour before sleep, particularly blue light from screens, makes a measurable difference for most people. Keeping the sleep environment cool and dark is more impactful than most people expect. And reducing stimulating content — including stressful news, intense social media, and absorbing entertainment — in the final hour of the day gives the nervous system time to shift toward rest.', 'This week: make one specific sleep change. Consistent bedtime, reduced screen time, darker room — pick one and hold it for seven days.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('59dc4f86-7a98-5285-8e98-b66e2d7d4f3a', '2a11ed68-3403-5716-8335-03076170f589', 1, 'How many hours of sleep are you averaging, and how do you feel in the morning — rested or still depleted?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('13c2c766-42b3-5d10-a745-1d60d085d4a2', '2a11ed68-3403-5716-8335-03076170f589', 2, 'What is the highest-leverage change you could make to your sleep this week — one specific, concrete change?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('04ae8bf4-3d92-5491-aa77-0fee06fb12b7', '2a11ed68-3403-5716-8335-03076170f589', 3, 'What gets in the way of prioritizing sleep — what beliefs or habits consistently push bedtime later than you intend?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('58bc71c2-4a4f-5a49-b5bd-f280c522dfb6', '895a0ed5-104a-506f-956b-1ff480b69b61', 5, 'Movement that fits your real life', 'Movement is one of the most well-supported health interventions available — with benefits across mental health, physical health, cognitive function, and longevity. It is also one of the most commonly abandoned health habits, because the version most people try to sustain is not built for their real life. The gym routine that requires forty-five minutes plus travel. The running plan that demands going out in bad weather. The class that requires coordination with a schedule that never quite aligns. These versions of movement are not wrong. They are simply designed for a more spacious life than most people actually have, and they are the first things to go when the inevitable busy week arrives. Movement that sticks is movement that fits. It happens in the actual windows available in your actual schedule. It does not require special equipment or a specific location. It can be adjusted in intensity based on how you feel on a given day without feeling like you have failed. It is something you can actually imagine doing for the next ten years. Walking is the most universally underrated movement practice available. Fifteen to thirty minutes of deliberate walking most days is supported by extensive research and accessible to almost everyone. If you have no current movement practice, starting with walking is not a concession to low ambition. It is the highest-probability path to building a sustained movement habit.', 'This week: commit to movement three times. Specific days, specific form, duration that is honest about your current capacity.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('3a918a50-d9bc-56a6-afc2-e1d3cd6c9de3', '58bc71c2-4a4f-5a49-b5bd-f280c522dfb6', 1, 'What movement have you most consistently sustained in your life — what form of movement fits you best?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('c0cc8805-722c-501e-acbb-f74dc53341dd', '58bc71c2-4a4f-5a49-b5bd-f280c522dfb6', 2, 'What is the most realistic movement practice for your actual schedule this week — specific days, specific duration, specific form?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('ac3eb276-5920-539e-8a12-a01dca666710', '58bc71c2-4a4f-5a49-b5bd-f280c522dfb6', 3, 'What would make it more likely that this movement continues into next week and the week after?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('daf87f4f-b8f5-5fb0-a45c-341f6196dc36', '895a0ed5-104a-506f-956b-1ff480b69b61', 6, 'Nutrition without overwhelm or rules', 'Nutrition is the health domain most cluttered with conflicting advice, moral language, and perfectionist expectations. You should eat this. You should not eat that. This food is clean. That one is bad. The cumulative effect of all of this is that many people feel simultaneously guilty about what they are eating and overwhelmed by the prospect of changing it. This path is not offering nutritional prescriptions. It is offering a different frame: nutrition as a form of care rather than a system of rules. What can you eat that genuinely nourishes you — that gives your body energy and stability and pleasure — in the context of your real life, with your real schedule, your real budget, and your real cooking capacity? The most impactful nutritional improvements are usually the simplest ones. More protein and fiber, which increase satiety and stabilize blood sugar. More water, which most people chronically underconsumed. Less ultra-processed food, not because it is morally wrong but because it is engineered to override satiation signals in ways that tend to produce more consumption than intended. And more attention to hunger and fullness — eating when hungry, stopping when satisfied — which is harder than it sounds in a world designed to make us eat regardless of hunger. One change at a time. The change that is most doable. That is the nutritional philosophy that produces lasting results.', 'This week: make one nutritional change. Not a diet. One thing that makes your eating slightly more nourishing than it currently is.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('f179449d-9312-5543-a9ce-73320cac3790', 'daf87f4f-b8f5-5fb0-a45c-341f6196dc36', 1, 'What one nutritional change would have the most meaningful impact on how you feel, and is realistic given your actual life?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('0c6e72ee-27cc-5495-9c81-80ea54ac370f', 'daf87f4f-b8f5-5fb0-a45c-341f6196dc36', 2, 'What is your relationship with food right now — is it mostly supportive, neutral, or complicated?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('3dfbaf33-2250-596d-a74e-43f895c537f9', 'daf87f4f-b8f5-5fb0-a45c-341f6196dc36', 3, 'What does good-enough nutrition look like for you, without requiring perfection or a complete overhaul?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('211fec5c-56c1-57f0-b717-ce2816b2b97d', '895a0ed5-104a-506f-956b-1ff480b69b61', 7, 'Linking new habits to existing ones', 'The most reliable way to build a new habit is to attach it to an existing one. This is called habit stacking, and it works because the existing habit provides the cue — reliably and automatically — that triggers the new one. You do not have to remember to do the new thing; the old thing reminds you. The formula is simple: After I do \[existing habit\], I will do \[new habit\]. After I make my morning coffee, I will drink one full glass of water first. After I sit down at my desk, I will spend two minutes writing what matters today. After I change out of work clothes, I will do ten minutes of movement. After I brush my teeth at night, I will do three minutes of deliberate breathing. The existing habit acts as an anchor. It is already happening automatically, which means it costs you nothing to use it as a trigger. The new habit piggybacks on the existing infrastructure. Over time, the new habit becomes as automatic as the old one — and then you can stack another habit onto it. The key is choosing the right existing habit to attach to — one that happens consistently, in the right context, at the right time. And starting with one stack, not five. One new thing attached to one existing thing. That is enough to begin.', 'This week: design and implement one habit stack. Write it as the full sentence. Do it every day for seven days.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('b0bf7a75-8808-5876-b32c-fcf2c10d2901', '211fec5c-56c1-57f0-b717-ce2816b2b97d', 1, 'What are the most reliable and consistent habits in your current daily life — the ones that happen almost automatically?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('c618d7a2-978e-5d89-a845-686edfcef1bb', '211fec5c-56c1-57f0-b717-ce2816b2b97d', 2, 'Which new health habit could most naturally be attached to one of those existing habits?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('ddedd201-f0ed-56a5-bb7d-fcccf11d0a28', '211fec5c-56c1-57f0-b717-ce2816b2b97d', 3, 'What would the specific habit stack look like — After I \[existing habit\], I will \[new habit\]?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('b00dec38-8d01-5f3c-9b58-4e3d30e9e360', '895a0ed5-104a-506f-956b-1ff480b69b61', 8, 'Tracking progress without obsession', 'Tracking health habits is useful — it creates accountability, provides evidence of progress, and makes the pattern visible in ways that pure memory cannot. It is also, for some people, a route to a kind of perfectionism that becomes its own problem. The tracker that produces anxiety when imperfect, that turns a missed day into a crisis, that creates a relationship with health habits driven more by measurement than by actual wellbeing — that is not a useful tracker. The goal of tracking is to support the habit, not to become the habit. The simplest tracking is a check mark on a calendar — did I do this today, yes or no. That is enough data to see whether the habit is holding and whether the streak is building. More complex tracking — food logs, detailed fitness metrics, sleep score optimization — may be useful for some people and counterproductive for others. Know which type you are. If tracking genuinely motivates you and you can look at a missed day without it spiraling, track. If tracking has historically led to all-or-nothing thinking where a miss becomes abandonment, the check mark system is better. The measure of a good tracking system is whether it helps you maintain the habit. If it does, use it. If it creates more friction than the habit itself, simplify.', 'Closing commitment: Design your simple tracking system. Check marks or a brief daily note. Review it weekly. Adjust what is not working without drama. |');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('4f8797ad-2f10-5d60-94c7-eb89535597eb', 'b00dec38-8d01-5f3c-9b58-4e3d30e9e360', 1, 'What is your history with tracking health habits — has it helped, hurt, or been neutral?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('209b5037-47a1-5e0a-bdef-db930fc511c7', 'b00dec38-8d01-5f3c-9b58-4e3d30e9e360', 2, 'What is the simplest tracking system that would give you useful information without creating its own problems?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('26e666fc-1ef8-5596-90fd-9897f6b65375', 'b00dec38-8d01-5f3c-9b58-4e3d30e9e360', 3, 'Looking at the habits you have been building in this path, which ones are holding and which ones need more support?');
INSERT INTO public.path (id, name, description, tier, pillar, "subMode", "sessionsCount", classifications, "triggerSignals") VALUES ('c0a00b6c-1733-50f5-9960-72988e039666', 'Leading Under Pressure', 'Professional  ·  Executive Coaching  ·  High Output/Hidden Instability · Capacity Erosion', 'pro', 'professional', 'executive_coaching', 8, 'High Output/Hidden Instability · Capacity Erosion', 'enrollment:onboarding; flag:None — all users matching classification');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('dca0d92d-9087-54dd-bb77-14836124adf2', 'c0a00b6c-1733-50f5-9960-72988e039666', 1, 'What pressure does to leadership behavior', 'Pressure changes people. Under normal conditions, most leaders are capable of thoughtfulness, patience, strategic perspective, and genuine care for the people they lead. Under sustained pressure, the same leaders often become reactive, controlling, short, and present in a way that is physically in the room but not actually available. This is not a character flaw. It is a neurological reality. When the brain perceives threat — and sustained performance pressure registers as threat — it shifts resources from the prefrontal cortex, which handles nuanced thinking and interpersonal attunement, toward faster, more reactive systems. The result is a leader who is faster and more decisive but also less accurate, less empathetic, and less able to see the full picture. The problem with pressure-induced leadership degradation is that it is usually invisible to the person experiencing it. You feel like you are operating normally — just faster and more urgently. The people around you experience something different. They see the shorter fuse, the less open body language, the reduced availability for their concerns, the decisions made with less consultation. They often start self-managing around your state rather than bringing you what they need to bring you. Understanding what pressure does to your leadership behavior is the first step toward doing something about it.', 'This week: ask someone you trust how they experience you when you are under pressure. Listen without defending.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('f4f2a7ac-1004-5ee2-9245-470c9a6bd50d', 'dca0d92d-9087-54dd-bb77-14836124adf2', 1, 'When you are under significant pressure, what specifically changes about how you lead — what behaviors tend to show up?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('212aed44-9cce-56d3-8256-34dc5f849292', 'dca0d92d-9087-54dd-bb77-14836124adf2', 2, 'How do you know when you are in a pressure-affected leadership state — what are your personal signals?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('d17cb42a-859d-5228-a899-752c78496c87', 'dca0d92d-9087-54dd-bb77-14836124adf2', 3, 'What impact do you think your pressure state has had on the people around you — what might they have experienced that you may not have fully seen?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('94a8aabb-8549-5986-ac5a-4caab713ef1f', 'c0a00b6c-1733-50f5-9960-72988e039666', 2, 'The reactive leader versus the responsive leader', 'Every leader has both a reactive mode and a responsive mode. Reactive mode is fast, automatic, and optimized for immediate threat resolution. Responsive mode is slower, more deliberate, and optimized for the quality of outcomes over time. Neither is always right — sometimes speed is exactly what is needed. But the leader who is chronically in reactive mode is making a large number of decisions and taking a large number of actions that will require correction later. The difference between reactive and responsive is not the presence or absence of urgency. Urgency is a legitimate feature of many leadership situations. The difference is whether there is any space — any at all — between what is happening and how you respond. Reactive leaders close that space entirely. Responsive leaders learn to create and protect it, even when everything is moving fast. Creating space does not mean being slow. It means having enough of a pause — even thirty seconds — to ask: Is this the response I actually want to make? Is this the signal I want to send to my team? Is this a decision I will be comfortable with tomorrow? These questions do not require lengthy deliberation. They require a moment''s intention. That moment is the difference between reactive and responsive.', 'This week: in one high-pressure moment, pause for thirty seconds before responding. Notice whether the pause changes the response.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('0bb6dfbc-940d-575e-bb56-2b808a4fecb1', '94a8aabb-8549-5986-ac5a-4caab713ef1f', 1, 'Think of a recent situation where your response as a leader was more reactive than you would have liked. What happened and what was the cost?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('29517fb4-d9a8-57c0-b791-207aaf14e28c', '94a8aabb-8549-5986-ac5a-4caab713ef1f', 2, 'What would a responsive version of that same situation have looked like — what would have been different?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('8fd1ae82-78a5-5901-9d97-e790aa0d284a', '94a8aabb-8549-5986-ac5a-4caab713ef1f', 3, 'What helps you create space between stimulus and response when you are under pressure — even briefly?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('e323f287-9548-5ee0-af64-078b242d4880', 'c0a00b6c-1733-50f5-9960-72988e039666', 3, 'Making good decisions when everything is urgent', 'Urgency is the enemy of good decisions. Not because speed is always wrong — sometimes the most important thing is speed. But urgency creates a pressure that causes the brain to narrow its focus, reduce its options, and default to the most familiar response rather than the most effective one. In a leadership context, this produces decisions that are fast and confident and often wrong in ways that take months to fully surface. The most effective leaders under pressure are distinguished not by how quickly they decide, but by how clearly they can identify, in a high-urgency environment, which decisions actually require speed and which ones are being treated as urgent because everything feels urgent. The skill is triage — not of tasks, but of decision timelines. Some decisions need to happen in the next hour. Some need to happen today. Some feel urgent but would actually benefit from sleeping on — decisions made by a tired brain at ten pm that a rested brain would have made differently at eight am. The ability to know the difference, and to protect the most important decisions from the most degraded cognitive conditions, is one of the highest-leverage leadership skills available.', 'This week: when a decision feels urgent, ask: does this actually have to happen in the next hour? If the answer is no, give it more time.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('5319bde8-5414-52b2-a735-0b09dcba6f49', 'e323f287-9548-5ee0-af64-078b242d4880', 1, 'Think of a recent decision you made under urgency that you later wished you had made differently. What would have changed with more time or better conditions?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('2cd0c631-7af5-549b-95bb-3fce85bd66d3', 'e323f287-9548-5ee0-af64-078b242d4880', 2, 'How do you currently distinguish between decisions that genuinely require speed and ones that feel urgent but actually have more time?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('b49b58e8-b71c-5baf-ba3b-5f4d7c0be058', 'e323f287-9548-5ee0-af64-078b242d4880', 3, 'What is one practice that would help you make better decisions in high-pressure moments — something you could actually implement?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('5b8e1e35-2be2-5b13-b9b3-2b75fee36470', 'c0a00b6c-1733-50f5-9960-72988e039666', 4, 'Protecting your team from your stress', 'Your stress is not private. As a leader, your emotional state is broadcast — through your tone, your body language, your availability, your responses to questions, your facial expression when you read an email. Your team is reading these signals constantly, whether you are aware of it or not. And the signal they receive shapes how they feel, how they function, and what they are willing to bring to you. A team that is regularly exposed to a leader''s unmanaged stress learns specific things over time: to not bring problems until they have already solved them, because bringing problems creates more stress; to manage around the leader''s state rather than engaging with it; to protect themselves from the emotional volatility by becoming less present, less honest, and less invested. These are rational adaptations to an unsafe environment — and they are expensive for the team''s function and for the organization. Protecting your team from your stress does not mean pretending you are not stressed. Teams are perceptive enough to see through that, and the dishonesty creates its own problems. It means taking responsibility for how your stress manifests in the room. It means having enough self-awareness to know when you are in a state that is affecting the environment, and enough skill to manage how that state shows up — even when you cannot eliminate the state itself.', 'This week: tell your team explicitly, in one situation, what you are carrying. Not to burden them — to reduce their vigilance about it. Notice what changes.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('a1389c55-24d3-5b8d-9406-52cd74bc1b47', '5b8e1e35-2be2-5b13-b9b3-2b75fee36470', 1, 'How do you think your stress currently manifests in your leadership environment — what signals are you sending that you may not intend?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('2ac6af66-236b-5b15-914f-e63f565d3221', '5b8e1e35-2be2-5b13-b9b3-2b75fee36470', 2, 'What has your team learned to do as a result of your stress states — what have they adapted around?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('a51c5599-d00b-5830-a9d1-d78c35462976', '5b8e1e35-2be2-5b13-b9b3-2b75fee36470', 3, 'What is one specific thing you could do differently to create more psychological safety for your team when you are under pressure?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('8360afe8-0c7d-57bf-98ce-12f22a26d206', 'c0a00b6c-1733-50f5-9960-72988e039666', 5, 'Clarity of communication when the stakes are high', 'Under pressure, communication tends to become either too sparse or too dense. Leaders either communicate less — assuming people can figure things out, not having time for the full conversation, sending quick messages that leave more questions than answers — or they over-communicate in ways that create noise rather than clarity. The stakes are high and the quality of communication degrades at exactly the moment when it matters most. High-stakes communication requires a different discipline. Not more words — clearer ones. Not longer explanations — better-structured ones. The discipline of saying exactly what people need to know, in the order they need to know it, and then stopping. The most common failure in high-pressure communication is assuming that because something is clear to you, it will be clear to your audience. Your context is not shared. What seems obvious from inside the full picture is often not visible from outside it. The question to ask before any high-stakes communication is: what does this person actually need to know in order to do what I need them to do? Not what I find interesting, not the full background, not my thinking process. What they need. In what order. With what level of specificity.', 'This week: before one high-stakes communication, ask: what does this person actually need to know? Write that down. Send that.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('b58ccfd7-60bb-59cb-93b6-930238dc03a6', '8360afe8-0c7d-57bf-98ce-12f22a26d206', 1, 'What tends to happen to your communication quality under pressure — does it become too sparse, too dense, or something else?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('f3f5940b-46fc-51bb-a636-1844de696238', '8360afe8-0c7d-57bf-98ce-12f22a26d206', 2, 'Think of a recent communication that did not land as intended under pressure. What was the gap between what you sent and what was received?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('eadf73c3-50aa-5875-97ae-91c5fbc9b586', '8360afe8-0c7d-57bf-98ce-12f22a26d206', 3, 'What one change to how you communicate under pressure would make the biggest difference for your team?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('94b95779-038b-59fd-8a68-3308b0e7005d', 'c0a00b6c-1733-50f5-9960-72988e039666', 6, 'Strategic thinking versus firefighting', 'Every leader has two modes of operation: strategic mode, where they are thinking about direction, priorities, and the bigger picture; and firefighting mode, where they are reacting to immediate problems, urgent requests, and whatever is most loudly demanding their attention. Both modes are necessary. The problem is that most leaders under pressure spend the vast majority of their time in firefighting mode, and almost none in strategic mode. This is not laziness or poor planning. It is a structural feature of leadership under pressure. The fires are real. They demand response. And the nature of firefighting is that it fills whatever space is available — if you do not deliberately protect strategic time, the fires will consume it. The consequence of chronic firefighting is a leadership style that is responsive but not directional. The team gets problems solved, but they do not get clarity about where they are going or why. They get decisions made, but not a coherent framework for making decisions themselves. They get management, but not leadership. Over time, the organization drifts — not because of bad intentions, but because the strategic work is not getting done. Protecting strategic time is not a luxury available only when things are quiet. It is a non-negotiable of effective leadership — more important, not less, under pressure.', 'This week: protect one 90-minute block for strategic thinking. No meetings, no email, no problems. Think about direction.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('8487c663-b8ab-5616-936c-2ddc636b7804', '94b95779-038b-59fd-8a68-3308b0e7005d', 1, 'What percentage of your current leadership time is genuinely strategic versus reactive and firefighting?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('65408441-e4d4-5ace-936e-ee72bb5e591d', '94b95779-038b-59fd-8a68-3308b0e7005d', 2, 'What strategic work — direction, priorities, longer-term thinking — is not happening because firefighting is consuming the time?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('9ed3421f-c52a-5bea-915f-cda48e9cc5f8', '94b95779-038b-59fd-8a68-3308b0e7005d', 3, 'What would it take to protect a consistent strategic time block in your week, even during a high-pressure period?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('0b49b88e-95e9-5208-987a-3e5cdc1f10f7', 'c0a00b6c-1733-50f5-9960-72988e039666', 7, 'Recovering your leadership capacity after a hard season', 'Leadership under sustained pressure is genuinely depleting. The emotional labor of managing a team''s state while managing your own. The decision volume. The visibility. The weight of being the person others look to for stability and direction when you are not sure you have stability and direction to offer. This is real, and it takes something. The leaders who sustain over time are not the ones who are immune to depletion. They are the ones who take recovery seriously as a professional practice — who build genuine restoration into their seasons rather than treating it as a reward that comes after everything is done. What does leadership capacity recovery actually look like? It is different for different people. For some it is genuine time off — time that is not monitored, not partially available, not checking in just in case. For some it is a specific practice — exercise, time in nature, creative work, anything that engages a different part of the brain. For some it is honest conversation with a peer or coach — not to solve problems, but to discharge the weight of carrying things. What it is not is more of the same thing with the intensity slightly reduced. Recovery requires a genuine shift — from output mode to restoration mode. And it requires the belief that taking recovery seriously is not a concession to weakness. It is how leadership capacity is maintained.', 'This week: schedule one genuine recovery block. Something that shifts you from output mode to restoration mode. Protect it.');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('66551a82-cf61-5ccd-9707-3c480fbccfaa', '0b49b88e-95e9-5208-987a-3e5cdc1f10f7', 1, 'What does your leadership capacity feel like right now — depleted, partially restored, or genuinely recovered?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('c974c61f-85a0-5ec6-bf0d-f94c5c89a054', '0b49b88e-95e9-5208-987a-3e5cdc1f10f7', 2, 'What has worked for you in the past to genuinely restore your leadership capacity — not just pause the depletion, but actually restore?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('73cd3b01-afa6-55c4-8cd2-03e579b135cf', '0b49b88e-95e9-5208-987a-3e5cdc1f10f7', 3, 'What is one thing you could do in the next two weeks to give your leadership capacity a real chance to recover?');
INSERT INTO public."pathSession" (id, "pathId", index, title, "coachingText", "microCommitment") VALUES ('a808fd48-edc4-5e67-9c27-eb56066d17df', 'c0a00b6c-1733-50f5-9960-72988e039666', 8, 'Leading sustainably — the practices that make durability possible', 'Sustainable leadership is not the same as easy leadership. There will always be hard seasons, high-pressure periods, and demands that exceed what feels comfortable. Sustainability does not mean the absence of difficulty. It means the presence of enough support, structure, and recovery that difficulty does not compound into collapse. The leaders who sustain for decades — who are still effective and still engaged deep into their careers — have almost universally built a set of practices that protect their capacity over time. They know their warning signs. They have non-negotiables around rest and recovery. They have relationships that provide honest feedback and genuine support. They have developed the ability to say no — to themselves and to others — when the addition would compromise the sustainability of everything else. This path began with understanding what pressure does to leadership behavior. It closes with the invitation to build something that will serve you not just through this particular hard season but through all of the seasons ahead. The practices that make leadership sustainable are worth building now — not after the next crisis, not when things settle down, but now. You are a leader worth sustaining. The people around you benefit from that sustainability. Build it deliberately.', 'Closing commitment: Write your sustainable leadership practices. Three to five things. Review them monthly. They are not aspirations — they are requirements. | | ALL 18 MVP PATHS COMPLETE Batch 1 (Paths 4–8) · Batch 2 (Paths 9–13) · Batch 3 (Paths 14–18) · Plus Paths 1–3 already complete Total sessions across all 18 paths: 129 sessions Each session: Coaching Text (Part 1\) · Reflection Questions (Part 2\) · Micro-Commitment (Part 3\) Uncloud360™  ·  Proven Under Pressure  ·  Dr. Sam  ·  April 2026  ·  Confidential | | :---:');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('39e8194f-2276-59c2-bd50-27b19fdefb01', 'a808fd48-edc4-5e67-9c27-eb56066d17df', 1, 'What are the three or four practices that, if consistently maintained, would most protect your ability to lead sustainably over the long term?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('ec0122f8-0573-54dc-a68b-8e1448109ff2', 'a808fd48-edc4-5e67-9c27-eb56066d17df', 2, 'What has this path revealed about your leadership under pressure that you want to hold onto — what is the most important thing you are taking away?');
INSERT INTO public."pathQuestion" (id, "sessionId", index, "questionText") VALUES ('94555383-f161-5eb0-b657-34d7a5247e41', 'a808fd48-edc4-5e67-9c27-eb56066d17df', 3, 'What is the one commitment you are making to your own sustainability as a leader — something specific and real?');
